return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-02-06 09:34:40+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'Borlabs Cookie v3','language'=>'da_DK','messages'=>['Backend / Providers / AlertThe selected <translation-key id="Provider">Provider</translation-key> is not available in the current language.'=>'Den valgte <translation-key id="Provider">Udbyder</translation-key> er ikke tilgængelig på det aktuelle sprog.','Backend / Dialog Appearance / Breadcrumb<translation-key id="Dialog-Appearance">Dialog - Appearance</translation-key>'=>'<translation-key id="Dialog-Appearance">Dialogboks - Udseende</translation-key>','Backend / Dialog Appearance / HeadlineReset <translation-key id="Dialog-Appearance-Settings">Dialog Appearance</translation-key> Settings'=>'Nulstil indstillinger for <translation-key id="Dialog-Appearance-Settings">Dialogboksens udseende</translation-key>','Backend / Dialog Settings / Breadcrumb<translation-key id="Dialog-Settings">Dialog - Settings</translation-key>'=>'<translation-key id="Dialog-Settings">Dialogboks - Indstillinger</translation-key>','Backend / Import & Export / Field<translation-key id="Dialog-Appearance">Dialog - Appearance</translation-key>'=>'<translation-key id="Dialog-Appearance">Dialogboks - Udseende</translation-key>','Backend / Page Manager / Site Title<translation-key id="Dialog-Appearance">Dialog - Appearance</translation-key>'=>'<translation-key id="Dialog-Appearance">Dialogboks - Udseende</translation-key>','Backend / Page Manager / Site Title<translation-key id="Dialog-Settings">Dialog - Settings</translation-key>'=>'<translation-key id="Dialog-Settings">Dialogboks - Indstillinger</translation-key>','Backend / Setup Assistant / Headline<translation-key id="Language-Switcher">Language Switcher</translation-key>'=>'<translation-key id="Language-Switcher">Sprogomskifter</translation-key>','Backend / Setup Assistant / TableConfiguring <translation-key id="Language-Switcher">Language Switcher</translation-key>'=>'Konfiguration af <translation-key id="Language-Switcher">Sprogomskifter</translation-key>','Backend / Setup Assistant / Button Title<translation-key id="Button-Start-Setup">Start Setup</translation-key>'=>'<translation-key id="Button-Start-Setup">Start opsætning</translation-key>','Backend / Setup Assistant / HeadlineCheck the <translation-key id="Legal-Pages">Legal Pages</translation-key> for Accuracy'=>'Se de <translation-key id="Legal-Pages">Juridiske sider</translation-key> for nøjagtighed','Backend / Setup Assistant / Headline<translation-key id="Legal-Pages">Legal Pages</translation-key>'=>'<translation-key id="Legal-Pages">Juridiske sider</translation-key>','Backend / Setup Assistant / TableDetecting <translation-key id="Legal-Pages">Legal Pages</translation-key>'=>'Registrering af <translation-key id="Legal-Pages">Juridiske sider</translation-key>','Backend / Setup Assistant / Things to know / HeadlineAbout the <translation-key id="Legal-Pages">Legal Pages</translation-key>'=>'Om de <translation-key id="Legal-Pages">Juridiske sider</translation-key>','Backend / Setup Assistant / HeadlineWhat Kind of Setup Do You Prefer?'=>'Hvilken slags opsætning foretrækker du?','Backend / Setup Assistant / Breadcrumb<translation-key id="Setup-Mode-Custom-Setup">Custom Setup</translation-key>'=>'<translation-key id="Setup-Mode-Custom-Setup">Brugerdefineret opsætning</translation-key>','Backend / Setup Assistant / Breadcrumb<translation-key id="Setup-Mode-Guided-Setup">Guided Setup</translation-key>'=>'<translation-key id="Setup-Mode-Guided-Setup">Guidet opsætning</translation-key>','Backend / Setup Assistant / Breadcrumb<translation-key id="Setup-Mode-Quick-Setup">Quick Setup</translation-key>'=>'<translation-key id="Setup-Mode-Quick-Setup">Hurtig opsætning</translation-key>','Backend / Setup Assistant / Option<translation-key id="Setup-Mode-Custom-Setup">Custom Setup</translation-key>'=>'<translation-key id="Setup-Mode-Custom-Setup">Brugerdefineret opsætning</translation-key>','Backend / Setup Assistant / Option<translation-key id="Setup-Mode-Guided-Setup">Guided Setup</translation-key>'=>'<translation-key id="Setup-Mode-Guided-Setup">Guidet opsætning</translation-key>','Backend / Setup Assistant / Option<translation-key id="Setup-Mode-Quick-Setup">Quick Setup</translation-key>'=>'<translation-key id="Setup-Mode-Quick-Setup">Hurtig opsætning</translation-key>','Backend / Setup Assistant / TextThe <translation-key id="Setup-Mode-Custom-Setup">Custom Setup</translation-key> installs all required packages and asks for basic settings like privacy page, logo, and dialog color.'=>'Den <translation-key id="Setup-Mode-Custom-Setup">Brugerdefinerede opsætning</translation-key> installerer alle nødvendige pakker og beder om grundlæggende indstillinger som privatlivsside, logo og dialogfarve.','Backend / Setup Assistant / TextThe <translation-key id="Setup-Mode-Guided-Setup">Guided Setup</translation-key> explains Borlabs Cookie basics, installs all required packages, and asks for basic settings like privacy page, logo, and dialog color.'=>'Den <translation-key id="Setup-Mode-Guided-Setup">Guidede opsætning</translation-key> forklarer det grundlæggende i Borlabs Cookie, installerer alle nødvendige pakker og beder om grundlæggende indstillinger som privatlivsside, logo og dialogfarve.','Backend / Setup Assistant / TextThe <translation-key id="Setup-Mode-Quick-Setup">Quick Setup</translation-key> automatically configures settings and installs all required packages.'=>'Den <translation-key id="Setup-Mode-Quick-Setup">Hurtige opsætning</translation-key> konfigurerer automatisk indstillinger og installerer alle nødvendige pakker.','Backend / Display Mode Settings Toggle / LabelDisplay Mode Settings'=>'Indstillinger for skærmtilstand','Backend / Display Mode Settings / Optiona) <translation-key id="Display-Mode-Settings-Simplified">Simplified</translation-key>'=>'a) <translation-key id="Display-Mode-Settings-Simplified">Forenklet</translation-key>','Backend / Display Mode Settings / Optionb) <translation-key id="Display-Mode-Settings-Standard">Standard</translation-key>'=>'b) <translation-key id="Display-Mode-Settings-Standard">Standard</translation-key>','Backend / Dialog Settings / Things to know / Text<translation-key id="Language-Switcher-Name">Name</translation-key>: Enter the name of the language, e.g. <strong><em>Deutsch</em></strong>.'=>'<translation-key id="Language-Switcher-Name">Navn</translation-key>: Indtast navnet på sproget, f.eks. <strong><em>Deutsch</em></strong>.','Backend / Library / Things to know<translation-key id="Auto-Update-Settings">Auto Update Settings</translation-key>'=>'<translation-key id="Auto-Update-Settings">Indstillinger for automatisk opdatering</translation-key>','Backend / Library / Things to knowAuto Update Symbol'=>'Symbol for automatisk opdatering','Backend / Library / Things to knowThe symbol indicates that automatic updates are enabled for this package.'=>'Symbolet viser, at automatiske opdateringer er aktiveret for denne pakke.','Backend / Init / Alert Message<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> is not active. If you want to use <translation-key id="Borlabs-Cookies">Borlabs Cookie\'s</translation-key> features on your website, please activate it under <translation-key id="Navigation-Settings">Settings</translation-key> &raquo; <translation-key id="Navigation-Settings-General-Settings">General Settings</translation-key> &raquo; <translation-key id="Borlabs-Cookie-Status">Borlabs Cookie Status</translation-key>.'=>'<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> er ikke aktiv. Hvis du vil bruge <translation-key id="Borlabs-Cookies">Borlabs Cookies</translation-key> funktioner på din hjemmeside, skal du aktivere den under <translation-key id="Navigation-Settings">Indstillinger</translation-key> &raquo; <translation-key id="Navigation-Settings-General-Settings">Generelle indstillinger</translation-key> &raquo; <translation-key id="Borlabs-Cookie-Status">Borlabs Cookie-status</translation-key>.','Backend / Init / Plugin LinksSetup Assistant'=>'Assistent til opsætning','Backend / Display Mode Settings Toggle / Alert MessageYou\'re currently seeing fewer options because the <translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key> is set to <translation-key id="Display-Mode-Settings-Simplified">Simplified</translation-key>.<br>To view all options, temporarily switch to <translation-key id="Display-Mode-Settings-Standard">Standard</translation-key> by turning off the toggle on the left, or permanently change it under <translation-key id="Navigation-Settings">Settings</translation-key> &raquo; <translation-key id="Navigation-Settings-Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key>.'=>'Du ser i øjeblikket færre muligheder, fordi <translation-key id="Display-Mode-Settings">Visningstilstand for indstillinger</translation-key> er indstillet til <translation-key id="Display-Mode-Settings-Simplified">Forenklet</translation-key>.<br>For at se alle muligheder skal du midlertidigt skifte til <translation-key id="Display-Mode-Settings-Standard">Standard</translation-key> ved at slå knappen til venstre fra eller ændre den permanent under <translation-key id="Navigation-Settings">Indstillinger</translation-key> &raquo; <translation-key id="Navigation-Settings-Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key>.','Backend / Page Manager / Menu Title- Admin &amp; Plugin Settings'=>'- Indstillinger for administration og plugins','Backend / Page Manager / Menu Title- General Settings'=>'- Generelle indstillinger','Backend / Page Manager / Menu Title- Setup Assistant'=>'- Assistent til opsætning','Backend / Page Manager / Site TitleAdmin &amp; Plugin Settings'=>'Indstillinger for administration og plugins','Backend / Page Manager / Site TitleGeneral Settings'=>'Generelle indstillinger','Backend / Page Manager / Site TitleLibrary - Manage'=>'Bibliotek - Administrer','Backend / Page Manager / Site TitleLibrary - Settings'=>'Bibliotek - Indstillinger','Backend / Page Manager / Site TitleSetup Assistant'=>'Assistent til opsætning','Backend / System Check / Alert MessageThe <translation-key id="Compatibility-Patches">Compatibility Patches</translation-key> are disabled by the <strong>BORLABS_COOKIE_ENABLE_SAFE_MODE</strong> constant.'=>'<translation-key id="Compatibility-Patches">Kompatibilitetsrettelserne</translation-key> er deaktiveret af <strong>BORLABS_COOKIE_ENABLE_SAFE_MODE-konstanten</strong>.','Backend / System Check / Alert MessageThe <translation-key id="Compatibility-Patches">Compatibility Patches</translation-key> are disabled by the <strong>borlabsCookieSafeModeHash</strong> cookie.'=>'<translation-key id="Compatibility-Patches">Kompatibilitetsrettelserne</translation-key> er deaktiveret af <strong>borlabsCookieSafeModeHash-cookien</strong>.','Backend / Setup Assistant / Things to know / TextFor best results, use a square (1:1) logo. Large logos may push the headline out of place or break the layout. A size around 128×128 px works well in most cases.'=>'Brug et kvadratisk (1:1) logo for at få det bedste resultat. Store logoer kan skubbe overskriften væk eller ødelægge layoutet. En størrelse på omkring 128×128 px fungerer godt i de fleste tilfælde.','Backend / Setup Assistant / Things to know / TextThe <translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key> determines how many configuration options are visible throughout the system.'=>'<translation-key id="Display-Mode-Settings">Visningstilstanden for indstillinger</translation-key> bestemmer, hvor mange konfigurationsmuligheder der er synlige i hele systemet.','Backend / Setup Assistant / Things to know / TextYou can switch between modes at any time. Changing the display mode only affects which settings are visible. It does not modify your existing configurations or saved values.'=>'Du kan skifte mellem tilstande når som helst. Ændring af visningstilstand påvirker kun, hvilke indstillinger der er synlige. Det ændrer ikke dine eksisterende konfigurationer eller gemte værdier.','Backend / Setup Assistant / Things to know / TextThe <translation-key id="WordPress-Admin-Sidebar-Menu-Mode">WordPress Admin Sidebar Menu Mode</translation-key> determines which menu items are visible in the WordPress admin sidebar.'=>'<translation-key id="WordPress-Admin-Sidebar-Menu-Mode">Menutilstand for WordPress’ admin-sidebjælke</translation-key> bestemmer, hvilke menupunkter der er synlige i WordPress\' administratorsidebjælke.','Backend / Setup Assistant / Things to know / TextTask was successfully completed.'=>'Opgaven blev gennemført.','Backend / Setup Assistant / Things to know / TextTask failed to complete.'=>'Opgaven blev ikke fuldført.','Backend / Setup Assistant / Things to know / TextTask is waiting to be processed.'=>'Opgaven venter på at blive behandlet.','Backend / Setup Assistant / Things to know / TextTask was not required and skipped.'=>'Opgaven var ikke nødvendig og blev sprunget over.','Backend / Setup Assistant / URLhttps://borlabs.io/support/?utm_source=Borlabs+Cookie&utm_medium=Setup-Assistant+Link&utm_campaign=Analysis'=>'https://borlabs.io/support/?utm_source=Borlabs+Cookie&utm_medium=Setup-Assistant+Link&utm_campaign=Analysis','Backend / Setup Assistant / Things to know / Text<translation-key id="Language-Switcher-Code">Code</translation-key>: Enter the language code of the language you want to add, e.g. <strong><em>de</em></strong>. The language code must be in <translation-key id="ISO-639-1">ISO 639-1</translation-key> format. You can find a list of all language codes <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank"><strong><em>here</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'<translation-key id="Language-Switcher-Code">Kode</translation-key>: Indtast sprogkoden for det sprog, du vil tilføje, f.eks. <strong><em>de</em></strong>. Sprogkoden skal være i <translation-key id="ISO-639-1">ISO 639-1-format</translation-key>. Du kan finde en liste over alle sprogkoder <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank"><strong><em>her</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / Setup Assistant / Things to know / Text<translation-key id="Language-Switcher-URL">URL</translation-key>: Enter the URL of the page of the language.'=>'<translation-key id="Language-Switcher-URL">URL</translation-key>: Indtast URL\'en til sprogets side.','Backend / Setup Assistant / Things to know / TextThe <translation-key id="Language-Switcher">Language Switcher</translation-key> allows visitors to change the website\'s language using the <translation-key id="Dialog">Dialog</translation-key>. Once they choose a language, they\'re automatically taken to the website\'s version in that language. This feature requires a multilingual plugin or a <translation-key id="Multisite-Network">Multisite Network</translation-key>.'=>'<translation-key id="Language-Switcher">Sprogomskifteren</translation-key> giver besøgende mulighed for at ændre hjemmesidens sprog ved hjælp af <translation-key id="Dialog">Dialogboksen</translation-key>. Når de har valgt et sprog, kommer de automatisk til hjemmesidens version på det pågældende sprog. Denne funktion kræver et flersproget plugin eller et <translation-key id="Multisite-Network">Multisite Network</translation-key>.','Backend / Setup Assistant / Things to know / HeadlineWhat\'s the best logo size?'=>'Hvad er den bedste logostørrelse?','Backend / Setup Assistant / Things to know / HeadlineAbout <translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key>'=>'Om <translation-key id="Display-Mode-Settings">Visningstilstanden for indstillinger</translation-key>','Backend / Setup Assistant / Things to know / HeadlineAbout <translation-key id="WordPress-Admin-Sidebar-Menu-Mode">WordPress Admin Sidebar Menu Mode</translation-key>'=>'Om <translation-key id="WordPress-Admin-Sidebar-Menu-Mode">Menutilstand for WordPress’ administratorsidebjælke</translation-key>','Backend / Setup Assistant / Things to know / HeadlineSymbols explained'=>'Symboler forklaret','Backend / Setup Assistant / Things to know / TextThe layout and displayed buttons can be adjusted anytime in <translation-key id="Navigation-Dialog-Widget">Dialog &amp; Widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialog</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Settings">Settings</translation-key>.'=>'Layoutet og de viste knapper kan til enhver tid justeres i <translation-key id="Navigation-Dialog-Widget">Dialogboks og widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialog</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Settings">Indstillinger</translation-key>.','Backend / Setup Assistant / Things to know / TextEnsure that the pages or URLs for the imprint and the privacy policy have been correctly recognized. If they are not, update the URLs accordingly.'=>'Sørg for, at siderne eller URL\'erne for kontaktsiden og privatlivspolitikken er blevet genkendt korrekt. Hvis de ikke er det, skal du opdatere URL\'erne i overensstemmelse hermed.','Backend / Setup Assistant / Things to know / TextIn some countries an imprint is not required. In that case, you may ignore this setting or choose a contact page instead.'=>'I nogle lande er en kontaktside ikke påkrævet. I så fald kan du ignorere denne indstilling eller vælge en kontaktside i stedet.','Backend / Setup Assistant / Things to know / HeadlineAdditional background information'=>'Yderligere baggrundsinformation','Backend / Setup Assistant / Things to know / HeadlineAbout the color assistant'=>'Om farveassistenten','Backend / Setup Assistant / Things to know / HeadlineWhat is the purpose of the <translation-key id="Language-Switcher">Language Switcher</translation-key> section?'=>'Hvad er formålet med sektionen <translation-key id="Language-Switcher">Sprogomskifter</translation-key>?','Backend / Setup Assistant / Things to know / HeadlineInput fields explained'=>'Inputfelter forklaret','Backend / Setup Assistant / Things to know / HeadlineAbout the layouts'=>'Om layoutet','Backend / Setup Assistant / Things to know / TextFor further customization, go to <translation-key id="Navigation-Dialog-Widget">Dialog &amp; Widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialog</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Appearance">Appearance</translation-key>, where you\'ll find more options for colors, spacing, and rounding.'=>'For yderligere tilpasning skal du gå til <translation-key id="Navigation-Dialog-Widget">Dialog og widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialogboks</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Appearance">Udseende</translation-key>, hvor du finder flere muligheder for farver, afstand og afrunding.','Backend / Setup Assistant / Things to know / TextThe layout illustrations show what the dialog looks like when all action buttons (blue) are visible.'=>'Layoutillustrationerne viser, hvordan dialogboksen ser ud, når alle handlingsknapper (blå) er synlige.','Backend / Setup Assistant / Things to know / TextHere you\'ll find explanations, notes, and context that go beyond the short info texts directly next to a setting.'=>'Her finder du forklaringer, noter og kontekst, som går ud over de korte infotekster, der står direkte ved siden af en indstilling.','Backend / Setup Assistant / Things to know / TextThe Color Assistant helps you design the entire dialog using three basic colors.'=>'Farveassistenten hjælper dig med at designe hele dialogboksen ved hjælp af tre grundfarver.','Backend / Setup Assistant / TextIf you have any questions, visit our <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="%s" rel="nofollow noreferrer" target="_blank"><span>Knowledge Base</span><span class="brlbs-cmpnt-external-link-icon"></span></a>. If you can\'t find what you need, contact our support team.'=>'Hvis du har spørgsmål, kan du besøge vores <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="%s" rel="nofollow noreferrer" target="_blank"><span>vidensbase</span><span class="brlbs-cmpnt-external-link-icon"></span></a>. Hvis du ikke kan finde det, du har brug for, kan du kontakte vores støtte-team.','Backend / Setup Assistant / TextSetup is completing, please wait...'=>'Opsætningen er ved at være færdig, vent venligst ...','Backend / Setup Assistant / TextShows all Borlabs Cookie menu items. Best for users who want direct access to every settings page.'=>'Viser alle menupunkter i Borlabs Cookie. Bedst for brugere, der vil have direkte adgang til alle indstillingssider.','Backend / Setup Assistant / TextShows only the most essential Borlabs Cookie menu items. Ideal for non-technical users.'=>'Viser kun de vigtigste menupunkter i Borlabs Cookie. Ideel til ikke-tekniske brugere.','Backend / Setup Assistant / TextShows the commonly used Borlabs Cookie menu items. Best for advanced or technical users.'=>'Viser de almindeligt anvendte menupunkter i Borlabs Cookie. Bedst for avancerede eller tekniske brugere.','Backend / Setup Assistant / Things to know / TextThis section provides additional background information and helpful tips related to the current settings.'=>'Denne sektion giver yderligere baggrundsinformation og nyttige tips i forbindelse med de aktuelle indstillinger.','Backend / Setup Assistant / TextDuring installation, additional <translation-key id="Services">Services</translation-key> may be added. Review them under <translation-key id="Navigation-Consent-Management">Consent Management</translation-key> &raquo; <a class="brlbs-cmpnt-link" href="?page=borlabs-cookie-services" target="_blank"><translation-key id="Navigation-Consent-Management-Services">Services</translation-key></a>, and disable any you don\'t use.'=>'Under installationen kan der tilføjes yderligere <translation-key id="Services">Servicer</translation-key>. Gennemgå dem under <translation-key id="Navigation-Consent-Management">Samtykkehåndtering</translation-key> &raquo; <a class="brlbs-cmpnt-link" href="?page=borlabs-cookie-services" target="_blank"><translation-key id="Navigation-Consent-Management-Services">Servicer</translation-key></a>og deaktiver dem, du ikke bruger.','Backend / Setup Assistant / TextUse the audit scan to confirm there are no unwanted external connections. Go to <translation-key id="Navigation-Library-Scanner">Library &amp; Scanner</translation-key> &raquo; <a class="brlbs-cmpnt-link" href="?page=borlabs-cookie-cloud-scan" target="_blank"><translation-key id="Navigation-Scanner">Scanner</translation-key></a>, open the most recent <translation-key id="Audit">Audit</translation-key> scan job, and check the results.'=>'Brug audit-scanningen til at bekræfte, at der ikke er nogen uønskede eksterne forbindelser. Gå til <translation-key id="Navigation-Library-Scanner">Bibliotek og scanner</translation-key> &raquo; <a class="brlbs-cmpnt-link" href="?page=borlabs-cookie-cloud-scan" target="_blank"><translation-key id="Navigation-Scanner">Scanner</translation-key></a>, åbn det seneste <translation-key id="Audit">Audit-scanningsjob</translation-key>, og se resultaterne.','Backend / Setup Assistant / TextThe content can refer to individual settings as well as general contexts and background information, helping you to better understand <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> and use it in a targeted manner.'=>'Indholdet kan henvise til individuelle indstillinger såvel som generelle sammenhænge og baggrundsinformation, hvilket hjælper dig med bedre at forstå <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> og bruge den på en målrettet måde.','Backend / Setup Assistant / TextThe setup assistant automatically performs a scan and installs the required packages in the background.'=>'Assistenten til opsætning udfører automatisk en scanning og installerer de nødvendige pakker i baggrunden.','Backend / Setup Assistant / TextThe recommended and easiest settings are always preselected.'=>'De anbefalede og nemmeste indstillinger er altid forvalgt.','Backend / Setup Assistant / TextIn the next step, you will learn more about using <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.'=>'I næste trin lærer du mere om at bruge <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.','Backend / Setup Assistant / TextSetup is complete. The <translation-key id="Dialog">Dialog</translation-key> should now appear on your website.'=>'Opsætningen er færdig. <translation-key id="Dialog">Dialogboksen</translation-key> bør nu vises på din hjemmeside.','Backend / Setup Assistant / TextOpen your website in incognito/private mode and confirm everything works as intended.'=>'Åbn din hjemmeside i inkognito/privat tilstand, og bekræft, at alt fungerer efter hensigten.','Backend / Setup Assistant / TextCheck your mailbox for any follow-up instructions required by a package. If a package included instructions, they were sent to <strong><em>{{ mailRecipient }}</em></strong>.'=>'Tjek din postkasse for eventuelle opfølgningsinstruktioner, der kræves af en pakke. Hvis en pakke indeholdt instruktioner, blev de sendt til <strong><em>{{ mailRecipient }}</em></strong>.','Backend / Setup Assistant / TextYou can find additional information in the purple section &quot;<translation-key id="Things-to-know">Things to know</translation-key>&quot;. Depending on the view, this section is displayed to the right of or below the settings.'=>'Du kan finde yderligere oplysninger i den lilla sektion &quot;<translation-key id="Things-to-know">Værd at vide</translation-key>&quot;. Afhængigt af visningen vises denne sektion til højre for eller under indstillingerne.','Backend / Setup Assistant / TextIn the example, the first two buttons belong to the same form and apply <translation-key id="Example-Setting-A">Example Setting A</translation-key> and <translation-key id="Example-Setting-B">Example Setting B</translation-key>.'=>'I eksemplet hører de to første knapper til den samme formular og anvender <translation-key id="Example-Setting-A">Eksempel på indstilling A</translation-key> og <translation-key id="Example-Setting-B">Eksempel på indstilling B</translation-key>.','Backend / Setup Assistant / Text<translation-key id="Example-Setting-C">Example Setting C</translation-key> belongs to a different form. This is indicated by the separator line between the forms.'=>'<translation-key id="Example-Setting-C">Eksempel på indstilling C</translation-key> hører til en anden formular. Dette er angivet med separatoren mellem formularerne.','Backend / Setup Assistant / TextOnly the most essential settings are displayed. Ideal for non-technical users.'=>'Kun de vigtigste indstillinger vises. Ideel til ikke-tekniske brugere.','Backend / Setup Assistant / TextAll available settings are shown. Best for advanced or technical users.'=>'Alle tilgængelige indstillinger vises. Bedst til avancerede eller tekniske brugere.','Backend / Setup Assistant / TextThe info symbol next to a setting provides brief information about what the setting is for and what it does.'=>'Infosymbolet ved siden af en indstilling giver kort information om, hvad indstillingen er til, og hvad den gør.','Backend / Setup Assistant / TextEach form can have one or more blue buttons. This allows you to apply settings without scrolling through a long page. When several forms are on the same page, the separator line helps you see which settings belong together.'=>'Hver formular kan have en eller flere blå knapper. Det gør det muligt at anvende indstillinger uden at skulle scrolle gennem en lang side. Når flere formularer er på samme side, hjælper separatoren dig med at se, hvilke indstillinger der hører sammen.','Backend / Setup Assistant / TextTwo-column layout with content on the left and the <translation-key id="Service-Group">Service Group</translation-key> description on the right. On mobile, it adapts to the &quot;<strong>Box - Advanced</strong>&quot; layout.'=>'To-spaltet layout med indhold til venstre og beskrivelse af <translation-key id="Service-Group">Servicegruppen</translation-key> til højre. På mobilen tilpasser den sig &quot;<strong>Box - Advanced</strong>&quot; layout.','Backend / Setup Assistant / TextPress <translation-key id="Pagination-Next">Next</translation-key> to continue. The next steps will let you customize <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.'=>'Tryk på <translation-key id="Pagination-Next">Næste</translation-key> for at fortsætte. De næste trin giver dig mulighed for at tilpasse <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.','Backend / Setup Assistant / TextPress <translation-key id="Pagination-Next">Next</translation-key> to complete the setup. If it\'s not visible, scroll down slightly.'=>'Tryk på <translation-key id="Pagination-Next">Næste</translation-key> for at afslutte opsætningen. Hvis det ikke er synligt, skal du rulle lidt ned.','Backend / Setup Assistant / TextPress <translation-key id="Pagination-Next">Next</translation-key> to proceed to the next step.'=>'Tryk på <translation-key id="Pagination-Next">Næste</translation-key> for at gå videre til næste trin.','Backend / Setup Assistant / TextPurple buttons are used exclusively in the library within the details of a package to trigger package updates.'=>'Lilla knapper bruges udelukkende i biblioteket inden for detaljerne i en pakke til at udløse pakkeopdateringer.','Backend / Setup Assistant / TextWhenever you see the color purple for example as a purple circle with a number in the navigation it indicates that an update for a package is available.'=>'Når du ser farven lilla, f.eks. som en lilla cirkel med et tal i navigationen, betyder det, at en opdatering til en pakke er tilgængelig.','Backend / Setup Assistant / TextRed buttons are used for destructive actions, such as deleting or resetting data.'=>'Røde knapper bruges til destruktive handlinger, som f.eks. at slette eller nulstille data.','Backend / Setup Assistant / TextThese actions reload the page or redirect away from the current page after execution.'=>'Disse handlinger genindlæser siden eller omdirigerer væk fra den aktuelle side efter udførelse.','Backend / Setup Assistant / TextThe separator line shows where one form ends and another one begins. It appears automatically when there is more than one form on a page.'=>'Separatoren viser, hvor en formular slutter, og en anden begynder. Den vises automatisk, når der er mere end én formular på en side.','Backend / Setup Assistant / TextA bar-style layout with content on the left and action buttons on the right. On mobile, it adapts to the &quot;<strong>Box - Advanced</strong>&quot; layout.'=>'Et layout i stil med en bjælke med indhold til venstre og handlingsknapper til højre. På mobilen tilpasser den sig til &quot;<strong>Box - Advanced</strong>&quot; layout.','Backend / Setup Assistant / TextSimilar to the default layout, but displays all content at once. The user may need to scroll to reach the buttons. No <translation-key id="Service-Group">Service Group</translation-key> description.'=>'Svarer til standardlayoutet, men viser alt indhold på én gang. Brugeren skal muligvis scrolle for at nå knapperne. Ingen beskrivelse af <translation-key id="Service-Group">Servicegruppen</translation-key>.','Backend / Setup Assistant / TextDefault layout with scrollable content optimized for mobile. Displays the <translation-key id="Service-Group">Service Group</translation-key> description.'=>'Standardlayout med scrollbart indhold optimeret til mobil. Viser beskrivelsen af <translation-key id="Service-Group">Servicegruppen</translation-key>.','Backend / Setup Assistant / TextAlthough the <translation-key id="Debug-Console">Debug Console</translation-key> can be disabled in the <translation-key id="Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key> we recommend keeping it enabled.'=>'Selvom <translation-key id="Debug-Console">Debugging-konsol</translation-key> kan deaktiveres i <translation-key id="Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key>, anbefaler vi at holde den aktiveret.','Backend / Setup Assistant / TextGray buttons are used for navigation only, typically to go back to a previous view or overview.'=>'Grå knapper bruges kun til navigation, typisk til at gå tilbage til en tidligere visning eller oversigt.','Backend / Setup Assistant / TextClicking a grey button does not save any changes.'=>'At klikke på en grå knap gemmer ikke nogen ændringer.','Backend / Setup Assistant / TextThey are typically used for background processes (such as package installation or downloading the GeoIP database), for actions that update the user interface dynamically (like marking all checkboxes or updating a preview in the color assistant), and for closing modals or dialogs.'=>'De bruges typisk til baggrundsprocesser (som installation af pakker eller download af GeoIP-databasen), til handlinger, der opdaterer brugergrænsefladen dynamisk (som at markere alle Afkrydsningsfelter eller opdatere en forhåndsvisning i farveassistenten), og til at lukke modaler eller dialogbokse.','Backend / Setup Assistant / TextBlue buttons are used for actions that save changes and always reload or leave the current page.'=>'Blå knapper bruges til handlinger, der gemmer ændringer og altid genindlæser eller forlader den aktuelle side.','Backend / Setup Assistant / TextButton colors tell you what will happen before you click. They help you quickly understand actions, avoid unintended changes, and work with confidence.'=>'Knap-farver fortæller dig, hvad der vil ske, før du klikker. De hjælper dig med hurtigt at forstå handlinger, undgå utilsigtede ændringer og arbejde med selvtillid.','Backend / Setup Assistant / TextThe <translation-key id="Debug-Console">Debug Console</translation-key> is the fastest way to detect and resolve common errors.'=>'<translation-key id="Debug-Console">Debugging-konsollen</translation-key> er den hurtigste måde at opdage og løse almindelige fejl på.','Backend / Setup Assistant / TextIt is enabled by default and only visible to logged-in users with the <strong>Administrator</strong> role.'=>'Den er aktiveret som standard og kun synlig for indloggede brugere med rollen <strong>Administrator</strong>.','Backend / Setup Assistant / TextThe <translation-key id="Debug-Console">Debug Console</translation-key> opens automatically when an error is detected. If no issues are found, it remains collapsed at the bottom of your website.'=>'<translation-key id="Debug-Console">Debugging-konsollen</translation-key> åbnes automatisk, når der opdages en fejl. Hvis der ikke findes nogen problemer, forbliver den sammenklappet i bunden af din hjemmeside.','Backend / Setup Assistant / TextFor this purpose, packages from the <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> <translation-key id="Navigation-Library">Library</translation-key> are installed based on your website\'s <translation-key id="Theme">Theme</translation-key>, <translation-key id="Plugins">Plugins</translation-key>, and content.'=>'Til dette formål installeres pakker fra <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>-<translation-key id="Navigation-Library">Biblioteket</translation-key> baseret på din hjemmesides <translation-key id="Theme">Tema</translation-key>, <translation-key id="Plugins">Plugins</translation-key> og indhold.','Backend / Setup Assistant / TextThese packages ensure compatibility and provide a proper privacy-compliant integration.'=>'Disse pakker sikrer kompatibilitet og giver en ordentlig integration, der overholder privatlivets fred.','Backend / Setup Assistant / TextThe required packages are automatically determined using the <translation-key id="Navigation-Scanner">Scanner</translation-key>.'=>'De nødvendige pakker bestemmes automatisk ved hjælp af <translation-key id="Navigation-Scanner">scanneren</translation-key>.','Backend / Setup Assistant / TextBlack buttons are used for actions that execute immediately without leaving or reloading the current page.'=>'Sorte knapper bruges til handlinger, der udføres med det samme uden at forlade eller genindlæse den aktuelle side.','Backend / Setup Assistant / HintWhen <translation-key id="Text-Mode">Text Mode</translation-key> is enabled, placeholder text is displayed in the scheme instead of simple bars. This helps evaluate the legibility of the <translation-key id="Accent-Color">Accent Color</translation-key> and <translation-key id="Contrast-Color">Contrast Color</translation-key>.'=>'Når <translation-key id="Text-Mode">Teksttilstand</translation-key> er aktiveret, vises der pladsholdertekst i skemaet i stedet for simple bjælker. Dette hjælper med at evaluere læsbarheden af <translation-key id="Accent-Color">Accentfarven</translation-key> og <translation-key id="Contrast-Color">Kontrastfarven</translation-key>.','Backend / Setup Assistant / HintThis text demonstrates how additional information is shown.'=>'Denne tekst viser, hvordan yderligere information vises.','Backend / Setup Assistant / HintThe <translation-key id="Dialog">Dialog</translation-key> will not be shown on this page.'=>'<translation-key id="Dialog">Dialogboksen</translation-key> vises ikke på denne side.','Backend / Setup Assistant / HintMore information about <translation-key id="Example-Setting-A">Example Setting A</translation-key>.'=>'Flere oplysninger om <translation-key id="Example-Setting-A">Eksempel på indstilling A</translation-key>.','Backend / Setup Assistant / OptionBar - Advanced'=>'Bar - Advanced','Backend / Setup Assistant / OptionBox - Advanced'=>'Box - Advanced','Backend / Setup Assistant / OptionBox - Compact'=>'Box - Compact','Backend / Setup Assistant / OptionBox - Plus'=>'Box - Plus','Backend / Setup Assistant / TableRunning Cloud Scan'=>'Kører scanning til skyen','Backend / Setup Assistant / TablePreparing Page Detection'=>'Forberedelse af sideregistrering','Backend / Setup Assistant / TableIdentifying Packages'=>'Identificering af pakker','Backend / Setup Assistant / TableInstalling Packages'=>'Installation af pakker','Backend / Setup Assistant / TableLanguage'=>'Sprog','Backend / Setup Assistant / TableLanguage Code'=>'Sprogkode','Backend / Setup Assistant / TableRegister Audit Scan'=>'Registrer Audit-scanning','Backend / Setup Assistant / TableStarting Cloud Scan'=>'Start af scanning til skyen','Backend / Setup Assistant / TablePreparing Installation'=>'Forberedelse af installation','Backend / Setup Assistant / TableStatus'=>'Status','Backend / Setup Assistant / TableTask'=>'Opgave','Backend / Setup Assistant / TableURL'=>'URL','Backend / Setup Assistant / Text<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> helps make your website as privacy-compliant as possible automatically.'=>'<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> hjælper automatisk med at gøre din hjemmeside så privatlivskompatibel som muligt.','Backend / Setup Assistant / HintThe <translation-key id="Dialog-Background-Color">Dialog Background Color</translation-key> sets the primary background for the dialog and is also applied in lighter or darker variations to distinguish different areas within the dialog.'=>'<translation-key id="Dialog-Background-Color">Dialogboksens baggrundsfarve</translation-key> angiver den primære baggrund for dialogboksen og anvendes også i lysere eller mørkere variationer for at skelne mellem forskellige områder i dialogboksen.','Backend / Setup Assistant / Label<translation-key id="Example-Setting-B">Example Setting B</translation-key>'=>'<translation-key id="Example-Setting-B">Eksempel på indstilling B</translation-key>','Backend / Setup Assistant / Label<translation-key id="Example-Setting-C">Example Setting C</translation-key>'=>'<translation-key id="Example-Setting-C">Eksempel på indstilling C</translation-key>','Backend / Setup Assistant / Label<translation-key id="Imprint-Page">Imprint Page</translation-key>'=>'<translation-key id="Imprint-Page">Kontaktside</translation-key>','Backend / Setup Assistant / LabelLogo'=>'Logo','Backend / Setup Assistant / Label<translation-key id="Privacy-Page">Privacy Page</translation-key>'=>'<translation-key id="Privacy-Page">Side for privatlivspolitik</translation-key>','Backend / Setup Assistant / LabelShow the <translation-key id="Logo">Logo</translation-key> in the <translation-key id="Dialog">Dialog</translation-key>'=>'Vis <translation-key id="Logo">Logoet</translation-key> i <translation-key id="Dialog">dialogboksen</translation-key>','Backend / Setup Assistant / LabelTo start the setup, simply click the <translation-key id="Button-Start-Setup">Start Setup</translation-key> button.'=>'For at starte opsætningen skal du blot klikke på knappen <translation-key id="Button-Start-Setup">Start opsætning</translation-key>.','Backend / Setup Assistant / Headline<translation-key id="Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key>'=>'<translation-key id="Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key>','Backend / Setup Assistant / HeadlineBasic Concept'=>'Grundlæggende koncept','Backend / Setup Assistant / HeadlineThe Basic Concept of <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>'=>'Det grundlæggende koncept for <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>','Backend / Setup Assistant / Headline<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> Basics'=>'Grundlæggende om <translation-key id="Borlabs-Cookie">Borlabs Cookies</translation-key>','Backend / Setup Assistant / HeadlineButton Colors'=>'Farver på knapper','Backend / Setup Assistant / HeadlineButton Colors and Their Actions'=>'Farver på knapper og deres funktioner','Backend / Setup Assistant / HeadlineCheck the Language Switcher Options for Accuracy'=>'Tjek sprogomskifterens indstillinger for nøjagtighed','Backend / Setup Assistant / HeadlineChoose Your Preferred Layout for the Dialog'=>'Vælg dit foretrukne layout til dialogboksen','Backend / Setup Assistant / HeadlineChoose Your Preferred Mode'=>'Vælg din foretrukne tilstand','Backend / Setup Assistant / HeadlineColor Assistant'=>'Farveassistent','Backend / Setup Assistant / HeadlineConfigure Language'=>'Konfigurer sprog','Backend / Setup Assistant / Headline<translation-key id="Dialog-Appearance">Dialog - Appearance</translation-key>'=>'<translation-key id="Dialog-Appearance">Dialogboks - Udseende</translation-key>','Backend / Setup Assistant / HeadlineDialog Colors'=>'Dialogboksens farver','Backend / Setup Assistant / Headline<translation-key id="Dialog-Settings">Dialog - Settings</translation-key>'=>'<translation-key id="Dialog-Settings">Dialogboks - Indstillinger</translation-key>','Backend / Setup Assistant / HeadlineExample Settings'=>'Eksempel på indstillinger','Backend / Setup Assistant / HeadlineThe Fastest Way to Detect and Solve Common Issues'=>'Den hurtigste måde at registrere og løse almindelige problemer på','Backend / Setup Assistant / HeadlineFinalizing Installation'=>'Færdiggør installationen','Backend / Setup Assistant / HeadlineFirst Aid: Debug Console'=>'Førstehjælp: Debugging-konsol','Backend / Setup Assistant / HeadlineForm Separator'=>'Formular-separator','Backend / Setup Assistant / Headline<translation-key id="Layout">Layout</translation-key>'=>'<translation-key id="Layout">Layout</translation-key>','Backend / Setup Assistant / Headline<translation-key id="Logo">Logo</translation-key>'=>'<translation-key id="Logo">Logo</translation-key>','Backend / Setup Assistant / HeadlineSchematic Preview'=>'Skematisk forhåndsvisning','Backend / Setup Assistant / HeadlineSelect Colors for the Dialog'=>'Vælg farver til dialogboksen','Backend / Setup Assistant / HeadlineSelect Your Logo for the Dialog'=>'Vælg dit logo til dialogboksen','Backend / Setup Assistant / HeadlineThe Separator Line Between Forms'=>'Separatoren mellem formularer','Backend / Setup Assistant / Headline<translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key>'=>'<translation-key id="Display-Mode-Settings">Visningstilstand for indstillinger</translation-key>','Backend / Setup Assistant / HeadlineSettings Information'=>'Information om indstillinger','Backend / Setup Assistant / HeadlineSetup Assistant Workflow'=>'Assistent til opsætnings arbejdsgang','Backend / Setup Assistant / HeadlineSetup Completed'=>'Opsætning afsluttet','Backend / Setup Assistant / HeadlineWhere to Find Information About Settings'=>'Hvor finder jeg information om indstillinger?','Backend / Setup Assistant / HeadlineWelcome to the Setup Assistant'=>'Velkommen til assistenten til opsætning','Backend / Setup Assistant / Headline<translation-key id="WordPress-Admin-Sidebar-Menu-Mode">WordPress Admin Sidebar Menu Mode</translation-key>'=>'<translation-key id="WordPress-Admin-Sidebar-Menu-Mode">Menutilstand for WordPress’ admin-sidebjælke</translation-key>','Backend / Setup Assistant / HintThe <translation-key id="Accent-Color">Accent Color</translation-key> is primarily used as the background color for buttons, checkboxes, and tabs.'=>'<translation-key id="Accent-Color">Accentfarven</translation-key> bruges primært som baggrundsfarve for knapper, afkrydsningsfelter og faner.','Backend / Setup Assistant / HintThe <translation-key id="Contrast-Color">Contrast Color</translation-key> is primarily used for text displayed on backgrounds with the <translation-key id="Accent-Color">Accent Color</translation-key>.'=>'<translation-key id="Contrast-Color">Kontrastfarven</translation-key> bruges primært til tekst, der vises på baggrunde med <translation-key id="Accent-Color">Accentfarven</translation-key>.','Backend / Plugin Settings / URLhttps://borlabs.io/kb/debug-console-test-results-explained/?utm_source=Borlabs+Cookie&amp;utm_medium=Things+to+know&amp;utm_campaign=Analysis'=>'https://borlabs.io/kb/debug-console-test-results-explained/?utm_source=Borlabs+Cookie&amp;utm_medium=Things+to+know&amp;utm_campaign=Analysis','Backend / Rest Client / AlertAn error occurred while communicating with the WordPress REST API.'=>'Der opstod en fejl under kommunikationen med WordPress REST API.','Backend / Rest Client / AlertYour WordPress authentication cookie has expired. Please log out of WordPress and then log in again.'=>'Din WordPress-godkendelsescookie er udløbet. Log ud af WordPress, og log derefter ind igen.','Backend / Rest Client / AlertThe WordPress REST API is currently blocked. Please check your security plugins or settings and make sure the REST API is accessible.'=>'WordPress REST API er i øjeblikket blokeret. Tjek dine sikkerhedsplugins eller -indstillinger, og sørg for, at REST API\'en er tilgængelig.','Backend / Rest Client / Table HeadlineCode'=>'Kode','Backend / Rest Client / Table HeadlineMessage'=>'Besked','Backend / Settings / HeadlineConsent Settings'=>'Indstillinger for samtykke','Backend / Setup Assistant Follow-up / TextDuring setup, some packages were installed that may require follow-up work.'=>'Under opsætningen blev der installeret nogle pakker, som kan kræve opfølgende arbejde.','Backend / Setup Assistant Follow-up / TextBelow you will find information on the follow-up steps for the individual packages.'=>'Nedenfor finder du oplysninger om opfølgningstrinnene for de enkelte pakker.','Backend / Setup Assistant Follow-up / TextIf two packages mention the same steps, for example updating the CSS or clearing the cache using the same procedure, you only need to perform the step once.'=>'Hvis to pakker nævner de samme trin, f.eks. opdatering af CSS eller rydning af cachen ved hjælp af samme procedure, behøver du kun at udføre trinnet én gang.','Backend / Setup Assistant Follow-up / TextBorlabs Cookie: Follow-Up Work Needed for Some Packages'=>'Borlabs Cookie: Opfølgende arbejde nødvendigt for nogle pakker','Backend / Setup Assistant / Alert MessageNo <translation-key id="Language-Option">Language Option</translation-key> configured.'=>'Ingen <translation-key id="Language-Option">Sprogindstilling</translation-key> konfigureret.','Backend / Setup Assistant / BreadcrumbSetup Assistant'=>'Assistent til opsætning','Backend / Setup Assistant / Button TitleAdd Language Option'=>'Tilføj sprogindstilling','Backend / Setup Assistant / ButtonApply Colors'=>'Anvend farver','Backend / Setup Assistant / ButtonButton'=>'Knap','Backend / Setup Assistant / ButtonGo to Dashboard'=>'Gå til dashboard','Backend / Setup Assistant / Button TitleSelect or Upload Logo'=>'Vælg eller upload logo','Backend / Setup Assistant / ButtonUpdate Preview'=>'Opdater forhåndsvisning','Backend / Setup Assistant / Button TitleUse this media'=>'Brug dette medie','Backend / Setup Assistant / Label<translation-key id="Accent-Color">Accent Color</translation-key>'=>'<translation-key id="Accent-Color">Accentfarve</translation-key>','Backend / Setup Assistant / Label<translation-key id="Contrast-Color">Contrast Color</translation-key>'=>'<translation-key id="Contrast-Color">Kontrastfarve</translation-key>','Backend / Setup Assistant / Label<translation-key id="Dialog-Background-Color">Dialog Background Color</translation-key>'=>'<translation-key id="Dialog-Background-Color">Dialogboksens baggrundsfarve</translation-key>','Backend / Setup Assistant / Label<translation-key id="Text-Mode">Text Mode</translation-key>'=>'<translation-key id="Text-Mode">Teksttilstand</translation-key>','Backend / Setup Assistant / Label<translation-key id="Example-Setting-A">Example Setting A</translation-key>'=>'<translation-key id="Example-Setting-A">Eksempel på indstilling A</translation-key>','Backend / Plugin Settings / Things to know / TextThe <translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key> determines how many configuration options are visible throughout the system.'=>'<translation-key id="Display-Mode-Settings">Visningstilstanden for indstillinger</translation-key> bestemmer, hvor mange konfigurationsmuligheder der er synlige i hele systemet.','Backend / Plugin Settings / Things to know / Text<translation-key id="Display-Mode-Settings-Standard">Standard</translation-key>: All available settings are shown. Best for advanced or technical users.'=>'<translation-key id="Display-Mode-Settings-Standard">Standard</translation-key>: Alle tilgængelige indstillinger vises. Bedst til avancerede eller tekniske brugere.','Backend / Plugin Settings / Things to know / Text<translation-key id="Display-Mode-Settings-Simplified">Simplified</translation-key>: Only the most essential settings are displayed. Ideal for non-technical users.'=>'<translation-key id="Display-Mode-Settings-Simplified">Forenklet</translation-key>: Kun de vigtigste indstillinger vises. Ideel til ikke-tekniske brugere.','Backend / Plugin Settings / Things to know / TextYou can switch between modes at any time. Changing the display mode only affects which settings are visible. It does not modify your existing configurations or saved values.'=>'Du kan skifte mellem tilstande når som helst. Ændring af visningstilstand påvirker kun, hvilke indstillinger der er synlige. Det ændrer ikke dine eksisterende konfigurationer eller gemte værdier.','Backend / Plugin Settings / Things to know / Text<a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="%s" rel="nofollow noreferrer" target="_blank"><span>More information about <translation-key id="Debug-Console">Debug Console</translation-key></span><span class="brlbs-cmpnt-external-link-icon"></span></a>'=>'<a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="%s" rel="nofollow noreferrer" target="_blank"><span>Mere information om <translation-key id="Debug-Console">Debugging-konsollen</translation-key></span><span class="brlbs-cmpnt-external-link-icon"></span></a>','Backend / Plugin Settings / Things to know / HeadlineAbout <translation-key id="Automatic-Update">Automatic Update</translation-key>'=>'Om <translation-key id="Automatic-Update">Automatisk opdatering</translation-key>','Backend / Plugin Settings / Things to know / HeadlineWhat is the <translation-key id="Debug-Console">Debug Console</translation-key>?'=>'Hvad er <translation-key id="Debug-Console">Debugging-konsollen</translation-key>?','Backend / Plugin Settings / Things to know / HeadlineAbout <translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key>'=>'Om <translation-key id="Display-Mode-Settings">Visningstilstanden for indstillinger</translation-key>','Backend / Plugin Settings / Things to know / TextWhen enabled, the debug console appears at the bottom of your website while you are logged in as an administrator. It is not visible to regular visitors.'=>'Når den er aktiveret, vises Debugging-konsollen nederst på din hjemmeside, mens du er logget ind som administrator. Den er ikke synlig for almindelige besøgende.','Backend / Plugin Settings / Things to know / TextThe console automatically opens if one of its tests fails. In most cases, it also provides helpful hints about the possible cause of the issue.'=>'Konsollen åbnes automatisk, hvis en af dens tests mislykkes. I de fleste tilfælde giver den også nyttige hints om den mulige årsag til problemet.','Backend / Plugin Settings / Things to know / Text<translation-key id="All-versions">All versions</translation-key>: All updates are installed automatically. This option is recommended to keep your setup compliant, compatible, and secure.'=>'<translation-key id="All-versions">Alle versioner</translation-key>: Alle opdateringer installeres automatisk. Denne indstilling anbefales for at holde din opsætning kompatibel og sikker.','Backend / Plugin Settings / HintChoose which menu items are displayed in the WordPress admin sidebar. Show only essential items in <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Simplified">Simplified</translation-key> mode, a balanced selection in <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Standard">Standard</translation-key> mode, or all available items in <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Expanded">Expanded</translation-key> mode.'=>'Vælg, hvilke menupunkter der skal vises i WordPress-administratorens sidepanel. Vis kun vigtige elementer i <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Simplified">Forenklet</translation-key> tilstand, et afbalanceret udvalg i <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Standard">Standardtilstand</translation-key> eller alle tilgængelige elementer i <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Expanded">Udvidet</translation-key> tilstand.','Backend / Plugin Settings / HintChoose how settings are displayed across the system. Show all available options in <translation-key id="Display-Mode-Settings-Standard">Standard</translation-key> mode or only essential ones in <translation-key id="Display-Mode-Settings-Simplified">Simplified</translation-key> mode.'=>'Vælg, hvordan indstillingerne vises på tværs af systemet. Vis alle tilgængelige indstillinger i <translation-key id="Display-Mode-Settings-Standard">Standardtilstand</translation-key> eller kun de vigtige i <translation-key id="Display-Mode-Settings-Simplified">Forenklet</translation-key> tilstand.','Backend / Plugin Settings / HintManages how updates for the <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> WordPress plugin are handled. For more details, see the <translation-key id="Things-to-know">Things to know</translation-key> section.'=>'Administrerer, hvordan opdateringer til WordPress-plugin\'et <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> håndteres. For flere detaljer, se sektionen <translation-key id="Things-to-know">Værd at vide</translation-key>.','Backend / Plugin Settings / HintPlease confirm that you want to reset all <translation-key id="Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key> settings. They will be reset to their default settings.'=>'Bekræft, at du ønsker at nulstille alle indstillinger for <translation-key id="Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key>. De vil blive nulstillet til deres standardindstillinger.','Backend / Plugin Settings / BreadcrumbAdmin &amp; Plugin Settings'=>'Indstillinger for administration og plugins','Backend / Plugin Settings / HeadlineAdmin Settings'=>'Administratorindstillinger','Backend / Plugin Settings / HeadlineDebug Settings'=>'Fejlfindingsindstillinger','Backend / Plugin Settings / HeadlineReset Admin &amp; Plugin Settings'=>'Nulstil indstillinger for administrator og plugins','Backend / Plugin Settings / HeadlineUpdate Settings'=>'Opdater indstillinger','Backend / Plugin Settings / Field<translation-key id="Automatic-Update">Automatic Update</translation-key>'=>'<translation-key id="Automatic-Update">Automatisk opdatering</translation-key>','Backend / Plugin Settings / FieldEnable Debug Logging'=>'Aktivér fejllogning','Backend / Plugin Settings / Label<translation-key id="Display-Mode-Settings">Display Mode of Settings</translation-key>'=>'<translation-key id="Display-Mode-Settings">Visningstilstanden for indstillinger</translation-key>','Backend / Plugin Settings / Label<translation-key id="WordPress-Admin-Sidebar-Menu-Mode">WordPress Admin Sidebar Menu Mode</translation-key>'=>'<translation-key id="WordPress-Admin-Sidebar-Menu-Mode">Menutilstand for WordPress’ admin-sidebjælke</translation-key>','Backend / Plugin Settings / Alert MessageThe <translation-key id="Automatic-Update">Automatic Update</translation-key> setting is not set to <translation-key id="All-versions">All versions</translation-key>. We highly recommend that you set it to <translation-key id="All-versions">All versions</translation-key> to ensure that your setup is compliant, compatible, and secure.'=>'Indstillingen <translation-key id="Automatic-Update">Automatisk opdatering</translation-key> er ikke sat til <translation-key id="All-versions">Alle versioner</translation-key>. Vi anbefaler, at du sætter den til <translation-key id="All-versions">Alle versioner</translation-key> for at sikre, at din opsætning er i overensstemmelse med reglerne, kompatibel og sikker.','Backend / License / Things to know / TextAlso check the license details in the customer portal to make sure the website you\'re trying to register is not listed under <translation-key id="Blocked-Domain">Blocked Domain</translation-key>.'=>'Tjek også detaljerne om licensen i kundeportalen for at sikre, at den hjemmeside, du forsøger at registrere, ikke er opført under <translation-key id="Blocked-Domain">Blokerede domæner</translation-key>.','Backend / License / Things to know / TextIf registration doesn\'t work, go to the customer portal and remove a website from the license you want to use.'=>'Hvis registreringen ikke virker, skal du gå til kundeportalen og fjerne en hjemmeside fra den licens, du vil bruge.','Backend / License / Things to know / HeadlineWhen Registration Doesn\'t Work'=>'Når registrering ikke virker','Backend / Library Settings / BreadcrumbLibrary - Settings'=>'Bibliotek - Indstillinger','Backend / Library Settings / HeadlineReset Library Settings'=>'Nulstil bibliotekets indstillinger','Backend / Dialog Settings / Things to know / TextFor best results, use a square (1:1) logo. Large logos may push the headline out of place or break the layout. A size around 128×128 px works well in most cases.'=>'Brug et kvadratisk (1:1) logo for at få det bedste resultat. Store logoer kan skubbe overskriften væk eller ødelægge layoutet. En størrelse på omkring 128×128 px fungerer godt i de fleste tilfælde.','Backend / Global / Info Panel / Headline<translation-key id="Things-to-know">Things to know</translation-key>'=>'<translation-key id="Things-to-know">Værd at vide</translation-key>','Backend / Global / Radio Card SelectedSelected'=>'Udvalgt','Backend / Global / Pagination<translation-key id="Pagination-Next">Next</translation-key>'=>'<translation-key id="Pagination-Next">Næste</translation-key>','Backend / Global / Pagination<translation-key id="Pagination-Previous">Previous</translation-key>'=>'<translation-key id="Pagination-Previous">Tilbage</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Settings-Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key>'=>'<translation-key id="Navigation-Settings-Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Settings-General-Settings">General Settings</translation-key>'=>'<translation-key id="Navigation-Settings-General-Settings">Generelle indstillinger</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Library-Scanner">Library &amp; Scanner</translation-key>'=>'<translation-key id="Navigation-Library-Scanner">Bibliotek og scanner</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Library-Installed-Packages">Installed Packages</translation-key>'=>'<translation-key id="Navigation-Library-Installed-Packages">Installerede pakker</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Library-Manage">Manage</translation-key>'=>'<translation-key id="Navigation-Library-Manage">Administrer</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Library-Settings">Settings</translation-key>'=>'<translation-key id="Navigation-Library-Settings">Indstillinger</translation-key>','Backend / Global / Navigation Entry<translation-key id="Navigation-Setup-Assistant">Setup Assistant</translation-key>'=>'<translation-key id="Navigation-Setup-Assistant">Assistent til opsætning</translation-key>','Frontend / Global / TextBorlabs Cookie'=>'Borlabs Cookie','Backend / Dialog Settings / HintThe <translation-key id="Dialog">Dialog</translation-key> will not be shown on this page.'=>'<translation-key id="Dialog">Dialogboksen</translation-key> vises ikke på denne side.','Backend / Dialog Settings / Things to know / TextVisitors who don\'t see the <translation-key id="Dialog">Dialog</translation-key> are automatically treated as having consented to all <translation-key id="Services">Services</translation-key>.'=>'Besøgende, der ikke ser <translation-key id="Dialog">Dialogboksen</translation-key>, behandles automatisk som om de har samtykket til alle <translation-key id="Services">Servicer</translation-key>.','Backend / Dialog Settings / Things to know / HeadlineWhat\'s the best logo size?'=>'Hvad er den bedste logostørrelse?','Backend / Sidebar Navigation Mode / Optionc) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Expanded">Expanded</translation-key>'=>'c) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Expanded">Udvidet</translation-key>','Backend / Sidebar Navigation Mode / Optionb) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Standard">Standard</translation-key>'=>'b) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Standard">Standard</translation-key>','Backend / Sidebar Navigation Mode / Optiona) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Simplified">Simplified</translation-key>'=>'a) <translation-key id="WordPress-Admin-Sidebar-Menu-Mode-Simplified">Forenklet</translation-key>','Backend / Dashboard / Button TitleGo to Setup Assistant'=>'Gå til assistent til opsætning','Backend / Dashboard / TextGet Borlabs Cookie ready in minutes.'=>'Gør Borlabs Cookie klar på få minutter.','Frontend / IAB TCF Dialog / TextThe choices you make regarding the purposes and vendors listed in this notice are stored in a cookie named {{ iabTcfCookieName }} for up to {{ cookieLifetime }} days.'=>'De valg du træffer om de formål og leverandører, der angives i denne meddelelse, opbevares i en cookie med navnet {{ iabTcfCookieName }} i op til {{ cookieLifetime }} dage.','Backend / IAB TCF Cookie Box / TextCookie Information - Description'=>'Oplysninger om cookie - Beskrivelse','Frontend / Debug Console / TextDialog is not hidden'=>'Dialogboksen er ikke skjult','Frontend / Debug Console / TextThe base URL was included in the <translation-key id="Hide-Dialog-On-Pages">Hide Dialog on Pages</translation-key> list.'=>'Basis-URL\'en blev inkluderet i listen <translation-key id="Hide-Dialog-On-Pages">Skjul dialogboks på sider</translation-key>.','Frontend / Debug Console / TextThe <translation-key id="Hide-Dialog-On-Pages">Hide Dialog on Pages</translation-key> list automatically includes the configured <translation-key id="Imprint-Page">Imprint Page</translation-key> and <translation-key id="Privacy-Page">Privacy Page</translation-key> URLs.'=>'Listen <translation-key id="Hide-Dialog-On-Pages">Skjul dialogboks på sider</translation-key> indeholder automatisk de konfigurerede URL\'er til <translation-key id="Imprint-Page">Kontaktside</translation-key> og <translation-key id="Privacy-Page">Side for privatlivspolitik</translation-key>.','Frontend / Debug Console / TextThis is not an error if you intended to hide the dialog on this page.'=>'Dette er ikke en fejl, hvis du havde til hensigt at skjule dialogboksen på denne side.','Backend / Content Blockers Appearance / Label<translation-key id="Use-Individual-Content-Blocker-Styles">Use Individual Content Blocker Styles</translation-key>'=>'<translation-key id="Use-Individual-Content-Blocker-Styles">Brug individuelle stile for indholdsblokkere</translation-key>','Backend / Content Blockers Appearance / Things to know / TextYou can disable this behavior with the <translation-key id="Use-Individual-Content-Blocker-Styles">Use Individual Content Blocker Styles</translation-key> option.'=>'Du kan deaktivere denne adfærd med indstillingen <translation-key id="Use-Individual-Content-Blocker-Styles">Brug individuelle stile for indholdsblokkere</translation-key>.','Backend / Content Blockers Appearance / Hint<translation-key id="Content-Blockers">Content Blockers</translation-key> installed from the <translation-key id="Navigation-Library">Library</translation-key> will use their own color settings instead of the global color settings.'=>'<translation-key id="Content-Blockers">Indholdsblokkere</translation-key>, der installeres fra <translation-key id="Navigation-Library">Biblioteket</translation-key>, bruger deres egne farveindstillinger i stedet for de globale farveindstillinger.','Frontend / IAB TCF Dialog / HeadlineStorage Information'=>'Oplysninger om opbevaring','Frontend / IAB TCF Dialog / TextCookie Refresh'=>'Opdatering af cookie','Frontend / IAB TCF Dialog / DateDay'=>'Dag','Frontend / IAB TCF Dialog / DateDays'=>'Dage','Frontend / IAB TCF Dialog / DateLess than a day'=>'Mindre end en dag','Frontend / IAB TCF Dialog / DateMonth'=>'Måned','Frontend / IAB TCF Dialog / DateMonths'=>'Måneder','Frontend / IAB TCF Dialog / TextDomain'=>'Domæne','Frontend / IAB TCF Dialog / TextIdentifier'=>'Identifikator','Frontend / IAB TCF Dialog / TextLifetime'=>'Livstid','Frontend / IAB TCF Dialog / TextPurpose(s)'=>'Formål','Frontend / IAB TCF Dialog / TextNo'=>'Nej','Frontend / IAB TCF Dialog / TextYes'=>'Ja','Frontend / IAB TCF Dialog / TextType'=>'Type','Frontend / IAB TCF Dialog / TextCookie Storage'=>'Opbevaring af cookie','Frontend / IAB TCF Dialog / TextNon-Cookie Access'=>'Tilgængelighed uden cookie','Backend / IAB TCF Cookie Box / HeadlineStorage Information - Headline'=>'Oplysninger om opbevaring - Overskrift','Backend / IAB TCF Cookie Box / Table HeadlineCookie Refresh'=>'Opdatering af cookie','Backend / IAB TCF Cookie Box / TextDay'=>'Dag','Backend / IAB TCF Cookie Box / TextDays'=>'Dage','Backend / IAB TCF Cookie Box / TextLess than a day'=>'Mindre end en dag','Backend / IAB TCF Cookie Box / TextMonth'=>'Måned','Backend / IAB TCF Cookie Box / TextMonths'=>'Måneder','Backend / IAB TCF Cookie Box / Table HeadlineLifetime'=>'Livstid','Backend / IAB TCF Cookie Box / TextStatus - No'=>'Status - Nej','Backend / IAB TCF Cookie Box / TextStatus - Yes'=>'Status - Ja','Backend / IAB TCF Cookie Box / Table HeadlineCookie Storage'=>'Opbevaring af cookie','Backend / IAB TCF Cookie Box / Table HeadlineNon-Cookie Access'=>'Tilgængelighed uden cookie','Backend / Dialog Localization / HeadlineIAB TCF - Accessibility'=>'IAB TCF - Tilgængelighed','Backend / Dialog Localization / HeadlineIAB TCF - Vendor Details Table'=>'IAB TCF - Tabel med detaljer om leverandør','Frontend / Debug Console / Text<translation-key id="Script-Blocker">Script Blocker</translation-key> no misconfiguration'=>'<translation-key id="Script-Blocker">Scriptblokering</translation-key> ingen fejlkonfiguration','Frontend / Debug Console / Text<translation-key id="Content-Blocker">Content Blocker</translation-key>'=>'<translation-key id="Content-Blocker">Indholdsblokker</translation-key>','Frontend / Debug Console / TextThe following <translation-key id="Services">Services</translation-key> may be configured incorrectly'=>'Følgende <translation-key id="Services">Servicer</translation-key> kan være konfigureret forkert','Frontend / Debug Console / TextThe unlock code of the <translation-key id="Script-Blocker">Script Blocker</translation-key> must only be stored in the <translation-key id="Content-Blocker">Content Blocker</translation-key> - not in the associated <translation-key id="Service">Service</translation-key>.'=>'<translation-key id="Script-Blocker">Scriptblokeringens</translation-key> oplåsningskode må kun gemmes i <translation-key id="Content-Blocker">Indholdsblokkeren</translation-key> - ikke i den tilknyttede <translation-key id="Service">Service</translation-key>.','Frontend / Debug Console / TextTo resolve the issue, remove the unblock code of the <translation-key id="Script-Blocker">Script Blocker</translation-key> from the <translation-key id="Service">Service</translation-key>.'=>'For at løse problemet skal du fjerne blokeringen af <translation-key id="Script-Blocker">Scriptblokeringens</translation-key> kode fra <translation-key id="Service">Servicen</translation-key>.','Frontend / Debug Console / Text<translation-key id="Service">Service</translation-key>'=>'<translation-key id="Service">Service</translation-key>','Backend / Library / Alert MessageThis package requires <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> version <strong><em>{{ version }}</em></strong> or newer. You are currently using version <strong><em>{{ currentVersion }}</em></strong>. To install, update, or re-install the package, please update <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> to the latest version to ensure compatibility with the library.'=>'Denne pakke kræver <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> version <strong><em>{{ version }}</em></strong> eller nyere. Du bruger i øjeblikket version <strong><em>{{ currentVersion }}</em></strong>. For at installere, opdatere eller geninstallere pakken skal du opdatere <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> til den nyeste version for at sikre kompatibilitet med biblioteket.','Backend / Content Blockers Settings / HintEvery <translation-key id="Location">Location</translation-key> of a disabled <translation-key id="Content-Blocker">Content Blocker</translation-key> is added to the <translation-key id="Virtual-Hostnames-Exclusion-List">Virtual Hostnames Exclusion List</translation-key>. Additionally, a <translation-key id="Compatibility-Patch">Compatibility Patch</translation-key> or a third-party developer can add a <translation-key id="Hostname">Hostname</translation-key> to this list using a filter. When a <translation-key id="Hostname">Hostname</translation-key> is recognized the content will not be blocked.'=>'Hver <translation-key id="Location">Adresse</translation-key> for en deaktiveret <translation-key id="Content-Blocker">Indholdsblokker</translation-key> føjes til <translation-key id="Virtual-Hostnames-Exclusion-List">Liste over udelukkede virtuelle værtsnavne</translation-key>. Derudover kan en <translation-key id="Compatibility-Patch">Kompatibilitetsrettelse</translation-key> eller en tredjepartsudvikler føje et <translation-key id="Hostname">Værtsnavn</translation-key> til denne liste ved hjælp af et filter. Når et <translation-key id="Hostname">Værtsnavn</translation-key> genkendes, vil indholdet ikke blive blokeret.','Backend / Dialog Localization / LabelDialog Close Button - Label'=>'Knappen Luk dialogboks - Label','Backend / Dialog Localization / LabelRegion Services - Label'=>'Afsnit om Servicer - Label','Backend / Dialog Localization / LabelRegion Services - Explanation'=>'Afsnit om Servicer - Forklaring','Backend / Dialog Localization / LabelWidget Button - Label'=>'Widgetknap - Label','Backend / Dialog Localization / LabelAccessibility - Region TCF Vendor Consent History - Label'=>'Tilgængelighed - Afsnit om Samtykkehistorik fra TCF-leverandører - Label','Backend / Dialog Localization / LabelAccessibility - Region TCF Vendor Consent History - Explanation'=>'Tilgængelighed - Afsnit om Samtykkehistorik fra TCF-leverandører - Forklaring','Backend / Dialog Localization / LabelAccessibility - Region Vendors - Label'=>'Tilgængelighed - Afsnit om Leverandører - Label','Backend / Dialog Localization / LabelAccessibility - Region Vendors - Explanation'=>'Tilgængelighed - Afsnit om Leverandører - Forklaring','Backend / Global / Alert MessageAn error occurred while communicating with the Borlabs Service API. Navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>, and check the logs for more information.'=>'Der opstod en fejl under kommunikationen med Borlabs Service API. Gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>, og tjek logfilerne for at få flere oplysninger.','Frontend / Dialog / A11YClose dialog'=>'Luk dialogboks','Frontend / Dialog / A11YService list and Filter Option'=>'Liste over servicer og filtermulighed','Frontend / Dialog / A11YThis section contains a list of services for which you can provide consent. You can use the filter to narrow down the list by entering a search term. The list updates automatically as you type.'=>'Denne sektion indeholder en liste over servicer, som du kan give samtykke til. Du kan bruge filteret til at indsnævre listen ved at indtaste et søgeord. Listen opdateres automatisk, når du skriver.','Frontend / Dialog / A11YOpen Privacy Preferences Dialog'=>'Åbn dialogboks for Privatlivsindstillinger','Frontend / Dialog / A11YTCF Vendors Consents and Filter Option'=>'Samtykker og filtreringsmulighed for TCF-leverandører','Frontend / Dialog / A11YThis section contains a list of vendors along with information about your consent choices. You can use the filter to narrow down the list by entering a search term. The list updates automatically as you type.'=>'Denne sektion indeholder en liste over leverandører sammen med oplysninger om dine samtykkevalg. Du kan bruge filteret til at indsnævre listen ved at indtaste et søgeord. Listen opdateres automatisk, når du skriver.','Frontend / Dialog / A11YVendor List and Filter Option'=>'Liste over leverandører og filtermulighed','Frontend / Dialog / A11YThis section contains a list of vendors for which you can provide consent. You can use the filter to narrow down the list by entering a search term. The list updates automatically as you type.'=>'Denne sektion indeholder en liste over leverandører, som du kan give samtykke til. Du kan bruge filteret til at indsnævre listen ved at indtaste et søgeord. Listen opdateres automatisk, når du skriver.','Backend / Dashboard / HeadlineTelemetry data'=>'Telemetridata','Backend / Dashboard / TextWe collect telemetry data to ensure the quality, security and further development of our software. This data helps us to diagnose faults, analyze usage, further product development and provide support. <strong class="brlbs-cmpnt-important-text">No personal data</strong> is collected - all information is of a purely technical nature.'=>'Vi indsamler telemetridata for at sikre kvaliteten, sikkerheden og den videre udvikling af vores software. Disse data hjælper os med at diagnosticere fejl, analysere brugen, videreudvikle produktet og yde støtte. Der indsamles <strong class="brlbs-cmpnt-important-text">ingen personlige data</strong> - alle oplysninger er af rent teknisk karakter.','Backend / Library / HeadlineProgress &amp; Result'=>'Fremskridt og resultat','Frontend / Debug Console / TextREST endpoint is accessible'=>'REST-slutpunkt er tilgængeligt','Backend / Cloud Scan / Button TitleInstall Suggested Packages'=>'Installér de foreslåede pakker','Backend / Library / BreadcrumbInstalling Multiple Packages'=>'Installerer flere pakker','Backend / Library / HeadlineInstallation Result'=>'Resultat af installation','Backend / Library / HeadlineInstalling Multiple Packages'=>'Installerer flere pakker','Backend / Content Blockers Appearance / Label<translation-key id="Font-Size-Base">Font Size (Base)</translation-key>'=>'<translation-key id="Font-Size-Base">Skriftstørrelse (standard)</translation-key>','Backend / Dialog Appearance / Label<translation-key id="Font-Size-Base">Font Size (Base)</translation-key>'=>'<translation-key id="Font-Size-Base">Skriftstørrelse (standard)</translation-key>','Backend / Dialog Settings / Label<translation-key id="Font-Size-Base">Font Size (Base)</translation-key> for Descriptions'=>'<translation-key id="Font-Size-Base">Skriftstørrelse (standard)</translation-key> for beskrivelser','Backend / Dialog Settings / HeadlineAccessibility Settings'=>'Indstillinger for tilgængelighed','Backend / Dialog Settings / HintInstead of the calculated font size <strong><em>{{ calculatedFontSize }}</em></strong>, the font size <strong><em>{{ baseFontSize }}</em></strong> is used for most descriptions. To change the <translation-key id="Font-Size-Base">Font Size (Base)</translation-key> navigate to <translation-key id="Navigation-Dialog-Widget">Dialog &amp; Widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialog</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Appearance">Appearance</translation-key>.'=>'I stedet for den beregnede skriftstørrelse <strong><em>{{ calculatedFontSize }}</em></strong>bruges skriftstørrelsen <strong><em>{{ baseFontSize }}</em></strong> til de fleste beskrivelser. For at ændre <translation-key id="Font-Size-Base">Skriftstørrelsen (base)</translation-key> skal du gå til <translation-key id="Navigation-Dialog-Widget">Dialogboks og widget</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog">Dialogboks</translation-key> &raquo; <translation-key id="Navigation-Dialog-Widget-Dialog-Appearance">Udseende</translation-key>.','Backend / Library / Things to knowWhere settings are changed'=>'Hvor indstillinger ændres','Backend / Library / Things to knowIn the <translation-key id="Auto-Update-Settings">Auto Update Settings</translation-key> section, you can configure the package to prevent code and translation from being overwritten during automatic updates.'=>'I sektionen <translation-key id="Auto-Update-Settings">Indstillinger for automatisk opdatering</translation-key> kan du konfigurere pakken til at forhindre kode og oversættelse i at blive overskrevet under automatiske opdateringer.','Backend / Services / Headline<translation-key id="Additional-Settings">Additional Settings</translation-key>'=>'<translation-key id="Additional-Settings">Yderligere indstillinger</translation-key>','Backend / Settings / LabelDisable Borlabs Cookie on Pages'=>'Deaktivér Borlabs Cookie på sider','Backend / Settings / Hint<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> will not be enabled on the specified pages. Add one URL per line. You can use wildcards (*) to match multiple pages. Example: <strong><em>https://example.com/course/*</em></strong> or <strong><em>*/course/*</em></strong>.'=>'<translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> vil ikke blive aktiveret på de angivne sider. Tilføj én URL pr. linje. Du kan bruge asterisker (*) til at matche flere sider. Eksempel: <strong><em>https://example.com/course/*</em></strong> eller <strong><em>*/course/*</em></strong>.','Backend / Library / Things to knowAll settings can be found in the respective <translation-key id="Services">Services</translation-key> or <translation-key id="Content-Blockers">Content Blockers</translation-key> under &quot;<translation-key id="Additional-Settings">Additional Settings</translation-key>&quot;, where they are fully managed and saved.'=>'Alle indstillinger kan findes i de respektive <translation-key id="Services">Servicer</translation-key> eller <translation-key id="Content-Blockers">Indholdsblokkere</translation-key> under &quot;<translation-key id="Additional-Settings">Yderligere indstillinger</translation-key>&quot;, hvor de administreres og gemmes fuldt ud.','Backend / Library / Things to knowThe package detail view displays only a limited selection of settings, primarily mandatory fields designed for quick setup during the initial installation.'=>'Pakkens detaljevisning viser kun et begrænset udvalg af indstillinger, primært obligatoriske felter, der er designet til hurtig opsætning under den første installation.','Backend / Library / Things to knowWhile these settings are saved, they do not include all available options and are not intended to be modified during an update or reinstallation.'=>'Selv om disse indstillinger gemmes, omfatter de ikke alle tilgængelige muligheder og er ikke beregnet til at blive ændret under en opdatering eller geninstallation.','Backend / Library / Things to knowTo change a setting, please go to the appropriate section:'=>'Hvis du vil ændre en indstilling, skal du gå til den relevante sektion:','Backend / Library / Things to knowOverwrite settings explained'=>'Indstillinger for overskrivning forklaret','Backend / Library / Things to knowThe <translation-key id="Overwrite-Code">Overwrite Code</translation-key> and <translation-key id="Overwrite-Translation">Overwrite Translation</translation-key> settings are always enabled and are applied during updates and reinstalls.'=>'Indstillingerne <translation-key id="Overwrite-Code">Overskriv kode</translation-key> og <translation-key id="Overwrite-Translation">Overskriv oversættelse</translation-key> er altid aktiveret og anvendes under opdateringer og geninstallationer.','Backend / Library / Things to knowAs a result, they are automatically reactivated after a package has been updated or reinstalled.'=>'Derfor bliver de automatisk genaktiveret, når en pakke er blevet opdateret eller geninstalleret.','Backend / Library / Things to knowFor detailed information on these settings, click the <span class="bc-align-middle brlbs-cmpnt-info-icon"></span>-symbol next to them above.'=>'For detaljerede oplysninger om disse indstillinger, klik på <span class="bc-align-middle brlbs-cmpnt-info-icon"></span>-symbolet ved siden af dem ovenfor.','Backend / Library / Things to know<translation-key id="Service">Service</translation-key>: <em><translation-key id="Navigation-Consent-Management">Consent Management</translation-key> &raquo; <translation-key id="Navigation-Consent-Management-Services">Services</translation-key></em>'=>'<translation-key id="Service">Service</translation-key>: <em><translation-key id="Navigation-Consent-Management">Samtykkehåndtering</translation-key> &raquo; <translation-key id="Navigation-Consent-Management-Services">Servicer</translation-key></em>','Backend / Library / Things to knowThe package detail view is <span class="brlbs-cmpnt-important-text">not</span> the primary place to change settings for <translation-key id="Services">Services</translation-key> or <translation-key id="Content-Blockers">Content Blockers</translation-key>.'=>'Pakkens detaljevisning er <span class="brlbs-cmpnt-important-text">ikke</span> det primære sted at ændre indstillinger for <translation-key id="Services">Servicer</translation-key> eller <translation-key id="Content-Blockers">Indholdsblokkere</translation-key>.','Backend / Library / Alert MessageIf the <translation-key id="Services">Services</translation-key> included in the <translation-key id="Compatibility-Patch">Compatibility Patch</translation-key> are not used on the website, they must be disabled under <translation-key id="Navigation-Consent-Management">Consent Management</translation-key> &raquo; <translation-key id="Navigation-Consent-Management-Services">Services</translation-key> after installing or updating the package.'=>'Hvis de <translation-key id="Services">Servicer</translation-key>, der er inkluderet i <translation-key id="Compatibility-Patch">Kompatibilitetsrettelsen</translation-key>, ikke bruges på hjemmesiden, skal de deaktiveres under <translation-key id="Navigation-Consent-Management">Samtykkehåndtering</translation-key> &raquo; <translation-key id="Navigation-Consent-Management-Services">Servicer</translation-key> efter installation eller opdatering af pakken.','Backend / Library / Field<translation-key id="Overwrite-Code">Overwrite Code</translation-key>'=>'<translation-key id="Overwrite-Code">Overskriv kode</translation-key>','Backend / Library / Field<translation-key id="Overwrite-Translation">Overwrite Translation</translation-key>'=>'<translation-key id="Overwrite-Translation">Overskriv oversættelse</translation-key>','Backend / Library / Headline<translation-key id="Auto-Update-Settings">Auto Update Settings</translation-key>'=>'<translation-key id="Auto-Update-Settings">Indstillinger for automatisk opdatering</translation-key>','Backend / Library Settings / TextAn email address <span class="brlbs-cmpnt-important-text">must</span> always be provided, even if the <translation-key id="Auto-Update">Auto Update</translation-key> feature is not being used.'=>'Der <span class="brlbs-cmpnt-important-text">skal</span> altid oplyses en e-mailadresse, også selvom funktionen <translation-key id="Auto-Update">Automatisk opdatering</translation-key> ikke bruges.','Backend / Library / Things to know<translation-key id="Content-Blocker">Content Blocker</translation-key>: <em><translation-key id="Navigation-Blockers">Blockers</translation-key> &raquo; <translation-key id="Navigation-Blockers-Content-Blockers">Content Blockers</translation-key> &raquo; <translation-key id="Navigation-Blockers-Content-Blockers-Manage">Manage</translation-key></em>.'=>'<translation-key id="Content-Blocker">Indholdsblokker</translation-key>: <em><translation-key id="Navigation-Blockers">Blokkere</translation-key> &raquo; <translation-key id="Navigation-Blockers-Content-Blockers">Indholdsblokkere</translation-key> &raquo; <translation-key id="Navigation-Blockers-Content-Blockers-Manage">Administrér</translation-key></em>.','Backend / Dialog Appearance / HintWhen <translation-key id="Text-Mode">Text Mode</translation-key> is enabled, placeholder text is displayed in the scheme instead of simple bars. This helps evaluate the legibility of the <translation-key id="Accent-Color">Accent Color</translation-key> and <translation-key id="Contrast-Color">Contrast Color</translation-key>.'=>'Når <translation-key id="Text-Mode">Teksttilstand</translation-key> er aktiveret, vises der pladsholdertekst i skemaet i stedet for simple bjælker. Dette hjælper med at evaluere læsbarheden af <translation-key id="Accent-Color">Accentfarven</translation-key> og <translation-key id="Contrast-Color">Kontrastfarven</translation-key>.','Backend / Dialog Localization / LabelDialog Close Button - Explanation'=>'Knappen Luk dialogboks - Forklaring','Backend / Global / Alert MessageNo entry configured.'=>'Ingen indgang konfigureret.','Backend / Global / Button TitleDeselect all'=>'Fravælg alle','Backend / Global / Button TitleSelect all'=>'Vælg alle','Backend / Library / Alert MessageThis package <span class="brlbs-cmpnt-important-text">must</span> always be installed if recommended by the <translation-key id="Navigation-Scanner">Scanner</translation-key>.'=>'Denne pakke <span class="brlbs-cmpnt-important-text">skal</span> altid installeres, hvis det anbefales af <translation-key id="Navigation-Scanner">Scanneren</translation-key>.','Frontend / Debug Console / TextConfiguration not found at the specified URL'=>'Konfiguration ikke fundet på den angivne URL','Frontend / Dialog / A11YThis button closes the dialog. Its functionality is identical to the {{ entranceAcceptOnlyEssential }} button.'=>'Denne knap lukker dialogboksen. Dens funktion er identisk med knappen {{ entranceAcceptOnlyEssential }}.','Backend / Dialog Appearance / ButtonApply Colors'=>'Anvend farver','Backend / Dialog Appearance / ButtonUpdate Preview'=>'Opdater forhåndsvisning','Backend / Dialog Appearance / Label<translation-key id="Accent-Color">Accent Color</translation-key>'=>'<translation-key id="Accent-Color">Accentfarve</translation-key>','Backend / Dialog Appearance / Label<translation-key id="Contrast-Color">Contrast Color</translation-key>'=>'<translation-key id="Contrast-Color">Kontrastfarve</translation-key>','Backend / Dialog Appearance / Label<translation-key id="Dialog-Background-Color">Dialog Background Color</translation-key>'=>'<translation-key id="Dialog-Background-Color">Dialogboksens baggrundsfarve</translation-key>','Backend / Dialog Appearance / Label<translation-key id="Text-Mode">Text Mode</translation-key>'=>'<translation-key id="Text-Mode">Teksttilstand</translation-key>','Backend / Dialog Appearance / HeadlineColor Assistant'=>'Farveassistent','Backend / Dialog Appearance / HeadlineSchematic Preview'=>'Skematisk forhåndsvisning','Backend / Dialog Appearance / HintThe <translation-key id="Accent-Color">Accent Color</translation-key> is primarily used as the background color for buttons, checkboxes, and tabs.'=>'<translation-key id="Accent-Color">Accentfarven</translation-key> bruges primært som baggrundsfarve for knapper, afkrydsningsfelter og faner.','Backend / Dialog Appearance / HintThe <translation-key id="Contrast-Color">Contrast Color</translation-key> is primarily used for text displayed on backgrounds with the <translation-key id="Accent-Color">Accent Color</translation-key>.'=>'<translation-key id="Contrast-Color">Kontrastfarven</translation-key> bruges primært til tekst, der vises på baggrunde med <translation-key id="Accent-Color">Accentfarven</translation-key>.','Backend / Dialog Appearance / HintThe <translation-key id="Dialog-Background-Color">Dialog Background Color</translation-key> sets the primary background for the dialog and is also applied in lighter or darker variations to distinguish different areas within the dialog.'=>'<translation-key id="Dialog-Background-Color">Dialogboksens baggrundsfarve</translation-key> angiver den primære baggrund for dialogboksen og anvendes også i lysere eller mørkere variationer for at skelne mellem forskellige områder i dialogboksen.','Backend / Content Blockers / Headline<translation-key id="Additional-Settings">Additional Settings</translation-key>'=>'<translation-key id="Additional-Settings">Yderligere indstillinger</translation-key>','Backend / Rest Client / Table HeadlineHTTP Status Code'=>'HTTP-statuskode','Backend / Library / Alert MessageInstallation failed. Navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>, and check the logs for more information.'=>'Installation mislykkedes. Gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>, og tjek logfilerne for at få flere oplysninger.','Frontend / Debug Console / TextTo configure the <translation-key id="Plugin-URL">Plugin URL</translation-key>, navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Settings">Settings</translation-key> &raquo; <translation-key id="Plugin-URL">Plugin URL</translation-key>.'=>'For at konfigurere <translation-key id="Plugin-URL">Plugin-URL</translation-key> skal du gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Settings">Indstillinger</translation-key> &raquo; <translation-key id="Plugin-URL">Plugin-URL</translation-key>.','Frontend / Debug Console / TextTo automatically configure the <translation-key id="Plugin-URL">Plugin URL</translation-key>, navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Settings">Settings</translation-key>, and scroll down to the <translation-key id="Reset">Reset</translation-key> section. Once the reset is complete, re-enable the <translation-key id="Borlabs-Cookie-Status">Borlabs Cookie Status</translation-key> and ensure the protocol in the <translation-key id="Plugin-URL">Plugin URL</translation-key> is set to "{{ protocol }}".'=>'For automatisk at konfigurere <translation-key id="Plugin-URL">Plugin-URL</translation-key>\'en skal du gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Settings">Indstillinger</translation-key> og scrolle ned til sektionen <translation-key id="Reset">Nulstil</translation-key>. Når nulstillingen er gennemført, skal du genaktivere <translation-key id="Borlabs-Cookie-Status">Borlabs Cookie-status</translation-key> og sikre, at protokollen i <translation-key id="Plugin-URL">Plugin-URL</translation-key>\'en er indstillet til "{{ protocol }}".','Frontend / Debug Console / TextConfigured Protocol'=>'Konfigureret protokol','Frontend / Debug Console / TextProtocol of this website'=>'Protokol for denne hjemmeside','Backend / API Client / AlertThe operation cannot be completed because the installed version of Borlabs Cookie is outdated. Please update to the latest version to maintain compatibility with our API.'=>'Handlingen kan ikke gennemføres, fordi den installerede version af Borlabs Cookie er forældet. Opdatér til den nyeste version for at opretholde kompatibilitet med vores API.','Frontend / Debug Console / TextConfig is not loaded as intended.'=>'Konfig er ikke indlæst som forventet.','Frontend / Debug Console / TextThis is usually caused by a third party plugin that combines or minifies scripts. To identify the cause, disable all plugins and switch to a default theme. Then, enable each plugin and theme one by one to pinpoint the issue.'=>'Dette skyldes normalt et tredjepartsplugin, der kombinerer eller minificerer scripts. For at identificere årsagen skal du deaktivere alle plugins og skifte til et standardtema. Aktivér derefter hvert plugin og tema ét efter ét for at finde frem til problemet.','Backend / Settings / URLhttps://borlabs.io/kb/set-up-cross-domain-cookie/?utm_source=Borlabs+Cookie&amp;utm_medium=Things+to+know&amp;utm_campaign=Analysis'=>'https://borlabs.io/kb/set-up-cross-domain-cookie/?utm_source=Borlabs+Cookie&amp;utm_medium=Things+to+know&amp;utm_campaign=Analysis','Backend / Legacy Importer / FieldLoad library for backward compatibility'=>'Indlæs bibliotek for bagudkompatibilitet','Frontend / Debug Console / TextConfig is placed correctly'=>'Konfig er placeret korrekt','Frontend / Debug Console / TextCorrect Cookie <translation-key id="Secure-Attribute">Secure attribute</translation-key> Status'=>'Korrekt status for cookie <translation-key id="Secure-Attribute">Secure-attribut</translation-key>','Frontend / Debug Console / TextCurrent <translation-key id="GeoIP-Caching-Mode">GeoIP Caching Mode</translation-key> Status'=>'Nuværende status for <translation-key id="GeoIP-Caching-Mode">GeoIP-cachetilstand</translation-key>','Backend / Package Auto Update Failed Mail / TextLog in to your WordPress account, navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>, and check the log with the <translation-key id="Process-ID">Process ID</translation-key> "<strong>{{ processId }}</strong>" for more information.'=>'Log ind på din WordPress-konto, gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>, og tjek loggen med <translation-key id="Process-ID">Proces-id</translation-key>\'et "<strong>{{ processId }}</strong>" for at få flere oplysninger.','Backend / Third Party Importer / HeadlineCustom <translation-key id="Content-Blockers">Content Blockers</translation-key>'=>'Tilpassede <translation-key id="Content-Blockers">Indholdsblokkere</translation-key>','Backend / Third Party Importer / HeadlineCustom <translation-key id="Script-Blockers">Script Blockers</translation-key>'=>'Tilpassede <translation-key id="Script-Blockers">Scriptblokkere</translation-key>','Backend / Third Party Importer / HeadlineCustom <translation-key id="Services">Services</translation-key>'=>'Tilpassede <translation-key id="Services">Servicer</translation-key>','Backend / Third Party Importer / HeadlinePreset <translation-key id="Content-Blockers">Content Blockers</translation-key>'=>'Skabelon for <translation-key id="Content-Blockers">Indholdsblokkere</translation-key>','Backend / Third Party Importer / HeadlinePreset <translation-key id="Services">Services</translation-key>'=>'Skabelon for <translation-key id="Services">Servicer</translation-key>','Frontend / Debug Console / TextCookie <translation-key id="Secure-Attribute">Secure attribute</translation-key> is set correctly'=>'Cookie <translation-key id="Secure-Attribute">Secure-attribut</translation-key> er indstillet korrekt','Frontend / Debug Console / Text<translation-key id="GeoIP">GeoIP</translation-key>'=>'<translation-key id="GeoIP">GeoIP</translation-key>','Frontend / Debug Console / TextCurrent Cookie <translation-key id="Secure-Attribute">Secure attribute</translation-key> Status'=>'Nuværende status for cookie <translation-key id="Secure-Attribute">Secure-attribut</translation-key>','Frontend / Debug Console / TextCurrent <translation-key id="GeoIP">GeoIP</translation-key> Status'=>'Nuværende status for <translation-key id="GeoIP">GeoIP</translation-key>','Frontend / Debug Console / TextPlease verify that the <translation-key id="GeoIP">GeoIP</translation-key> countries are configured correctly.'=>'Kontrollér, at landene for <translation-key id="GeoIP">GeoIP</translation-key> er konfigureret korrekt.','Backend / Package Auto Update Failed Mail / TextThe automatic update of the package &quot;<strong>{{ packageName }}</strong>&quot; failed.'=>'Den automatiske opdatering af pakken &quot;<strong>{{ packageName }}</strong>&quot; mislykkedes.','Backend / Planned Package Auto Update Mail / TextAfter a successful import, you must manually verify the information and functionality of all custom <translation-key id="Content-Blockers">Content Blockers</translation-key>, <translation-key id="Providers">Providers</translation-key>, and <translation-key id="Services">Services</translation-key>.'=>'Efter en succesfuld import skal du manuelt bekræfte oplysningerne og funktionaliteten for alle tilpassede<translation-key id="Content-Blockers">Indholdsblokkere</translation-key>, <translation-key id="Providers">Udbydere</translation-key> og <translation-key id="Services">Servicer</translation-key>.','Backend / Planned Package Auto Update Mail / TextThe import of Borlabs Cookie Legacy was <strong>{{ importStatus }}</strong>.'=>'Importen af Borlabs Cookie Legacy var <strong>{{ importStatus }}</strong>.','Backend / Planned Package Auto Update Mail / Textunsuccessful'=>'mislykket','Backend / Planned Package Auto Update Mail / Textsuccessful'=>'succesfuld','Backend / Third Party Importer / TextThe preset components were imported successfully.'=>'Skabelonkomponenterne blev succesfuldt importeret.','Backend / Third Party Importer / TextSince the IDs of some components differ between Borlabs Cookie 2.0 and 3.0, you need to review and update the IDs in any custom JavaScript code you may have used.'=>'Fordi ID\'erne for nogle komponenter er forskellige mellem Borlabs Cookie 2.0 og 3.0, er du nødt til at gennemgå og opdatere ID\'erne i al tilpasset JavaScript-kode, du måtte have brugt.','Backend / Third Party Importer / TextBorlabs Cookie: Import report from Borlabs Cookie Legacy'=>'Borlabs Cookie: Rapport om import fra Borlabs Cookie Legacy','Backend / Third Party Importer / TextHowever, since Borlabs Cookie 3.0 requires additional information that was not included in Borlabs Cookie 2.0, you will need to manually review and complete the details of the imported components, such as the <translation-key id="Provider">Provider</translation-key> information.'=>'Men da Borlabs Cookie 3.0 kræver yderligere oplysninger, som ikke var inkluderet i Borlabs Cookie 2.0, skal du manuelt gennemgå og udfylde detaljerne i de importerede komponenter, såsom oplysningerne om <translation-key id="Provider">Udbyder</translation-key>.','Backend / Package Install Failed Mail / TextBorlabs Cookie: Automatic Installation of {{ packageName }} failed'=>'Borlabs Cookie: Automatisk installation af {{ packageName }} mislykkedes','Backend / Page Manager / Menu Title- Legacy Importer'=>'- Legacy Importer','Backend / Page Manager / Site TitleLegacy Importer'=>'Legacy Importer','Backend / Third Party Importer / HeadlineCustom components imported'=>'Tilpassede komponenter er importeret','Backend / Third Party Importer / HeadlineImport report from Borlabs Cookie Legacy'=>'Rapport om import fra Borlabs Cookie Legacy','Backend / Third Party Importer / HeadlinePreset components imported'=>'Skabelonkomponenter er importeret','Backend / Third Party Importer / Table HeadlineName'=>'Navn','Backend / Third Party Importer / Table HeadlineInstallation Status'=>'Installationsstatus','Backend / Third Party Importer / TextThe following custom components were imported successfully.'=>'Følgende tilpassede komponenter blev succesfuldt importeret.','Backend / Package Install Failed Mail / Table HeadlinePackage'=>'Pakke','Backend / Legacy Importer / Alert MessageThe data have not been imported successfully. Navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>, and check the logs for more information.'=>'Dataene er ikke blevet succesfuldt importeret. Gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>, og tjek logfilerne for at få flere oplysninger.','Backend / Legacy Importer / Alert MessageNo import data available.'=>'Ingen tilgængelige importdata.','Backend / Legacy Importer / BreadcrumbLegacy Importer'=>'Legacy Importer','Backend / Legacy Importer / ButtonImport'=>'Import','Backend / Legacy Importer / FieldConfirm the Import of Legacy Data'=>'Bekræft import af legacy-data','Backend / Legacy Importer / HeadlineContent Blockers'=>'Indholdsblokkere','Backend / Legacy Importer / HeadlineImport Data Preview'=>'Forhåndsvisning af importdata','Backend / Legacy Importer / HeadlineImport Legacy Data'=>'Importér legacy-data','Backend / Legacy Importer / HeadlineLegacy Settings'=>'Legacy-indstillinger','Backend / Legacy Importer / HeadlineScript Blockers'=>'Scriptblokkere','Backend / Legacy Importer / HeadlineService Groups'=>'Servicegrupper','Backend / Legacy Importer / HeadlineServices'=>'Servicer','Backend / Legacy Importer / HintImports the legacy data from Borlabs Cookie 2.x to Borlabs Cookie 3.x. Existing data will be overwritten.'=>'Importerer legacy-data fra Borlabs Cookie 2.x til Borlabs Cookie 3.x. Eksisterende data vil blive overskrevet.','Backend / Legacy Importer / HintLoads the JavaScript library to support the Borlabs Cookie Legacy API, ensuring backward compatibility with most JavaScript functions. After enabling this option, visit your website and check the browser console for any related messages.'=>'Indlæser JavaScript-biblioteket til understøttelse af Borlabs Cookie Legacy API, som sikrer bagudkompatibilitet med de fleste JavaScript-funktioner. Efter aktivering skal du gå til din hjemmeside og tjekke browserkonsollen for eventuelle relaterede meddelelser.','Backend / Legacy Importer / Table HeadlineLanguage'=>'Sprog','Backend / Legacy Importer / Table HeadlineLegacy ID'=>'Legacy-id','Backend / Legacy Importer / Table HeadlineName'=>'Navn','Backend / Legacy Importer / Table HeadlineNew ID'=>'Nyt ID','Backend / Package Auto Update Failed Mail / Table HeadlineInstalled Version'=>'Installeret version','Backend / Package Auto Update Failed Mail / Table HeadlineLatest Version'=>'Seneste version','Backend / Package Auto Update Failed Mail / Table HeadlinePackage'=>'Pakke','Backend / Global / Navigation Entry<translation-key id="Navigation-Legacy-Importer">Legacy Importer</translation-key>'=>'<translation-key id="Navigation-Legacy-Importer">Legacy Importer</translation-key>','Backend / Legacy Importer / Alert MessageThe data have been imported successfully.'=>'Dataene blev succesfuldt importeret.','Frontend / Debug Console / TextThe configuration of Borlabs Cookie was placed incorrectly on the website, causing it not to function properly. This often occurs with optimization settings or plugins that combine and minify scripts. To identify the cause, disable all plugins and switch to a default theme. Then, enable each plugin and theme one by one to pinpoint the issue.'=>'Konfigurationen af Borlabs Cookie blev placeret forkert på hjemmesiden, som gjorde, at den ikke fungerede korrekt. Dette sker ofte med optimeringsindstillinger eller plugins, der kombinerer og minificerer scripts. For at identificere årsagen skal du deaktivere alle plugins og skifte til et standardtema. Aktivér derefter hvert plugin og tema ét efter ét for at finde frem til problemet.','Frontend / Debug Console / TextConfigured Cookie Domain'=>'Konfigureret Cookie-domæne','Frontend / Debug Console / TextConfigured Hostname'=>'Konfigureret værtsnavn','Frontend / Debug Console / TextConfigured URL'=>'Konfigureret URL','Frontend / Debug Console / TextCorrect URL'=>'Korrekt URL','Frontend / Debug Console / TextHostname of this website'=>'Værtsnavn på denne hjemmeside','Frontend / Debug Console / TextCurrent Respect <translation-key id="Do-Not-Track">&quot;Do Not Track&quot;</translation-key> Status'=>'Nuværende status for Respektér <translation-key id="Do-Not-Track">&quot;Do Not Track&quot;</translation-key>','Frontend / Debug Console / TextThis debug console is only displayed to administrators and is not visible to visitors.'=>'Denne debugging-konsol vises kun for administratorer og er ikke synlig for besøgende.','Frontend / Debug Console / TextTo disable the debug console, navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-Settings">Settings</translation-key> &raquo; <translation-key id="Navigation-Settings-Admin-Plugin-Settings">Admin &amp; Plugin Settings</translation-key> and disable the setting <translation-key id="Enable-Debug-Console">Enable Debug Console</translation-key>.'=>'For at deaktivere debugging-konsollen skal du gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-Settings">Indstillinger</translation-key> &raquo; <translation-key id="Navigation-Settings-Admin-Plugin-Settings">Indstillinger for administration og plugins</translation-key> og deaktivere indstillingen <translation-key id="Enable-Debug-Console">Aktivér debugging-konsol</translation-key>.','Frontend / Debug Console / TextAs the setting is enabled in both Borlabs Cookie and your browser, the dialog is not displayed.'=>'Da indstillingen er aktiveret i både Borlabs Cookie og din browser, vises dialogboksen ikke.','Frontend / Debug Console / TextDomain'=>'Domæne','Frontend / Debug Console / TextThe HTML request is used to determine whether consent is required.'=>'HTML-anmodningen bruges til at afgøre, om der kræves samtykke.','Frontend / Debug Console / TextThe AJAX request is used to determine whether consent is required.'=>'AJAX-anmodningen bruges til at afgøre, om der kræves samtykke.','Frontend / Debug Console / TextA common mistake is including your own country in the list of countries where the dialog is hidden.'=>'En almindelig fejl er at inkludere sit eget land på listen over lande, hvor dialogboksen er skjult.','Frontend / Debug Console / TextGoogle Ads'=>'Google Adsa','Frontend / Debug Console / TextGoogle Analytics'=>'Google Analytics','Frontend / Debug Console / TextGoogle Analytics Script Blocker service is installed'=>'Google Analytics scriptblokkerservice er installeret','Frontend / Debug Console / TextGoogle dataLayer is empty'=>'Google dataLayer er tomt','Frontend / Debug Console / TextA Google tag is configured before the default consent settings are applied.'=>'Et Google-tag er konfigureret, før standardindstillingerne for samtykke anvendes.','Frontend / Debug Console / TextGoogle Tag Manager local caching'=>'Google Tag Manager lokal caching','Frontend / Debug Console / TextConsent Mode is disabled'=>'Samtykketilstand er deaktiveret','Frontend / Debug Console / TextGoogle Tag Manager ID'=>'Google Tag Manager ID','Frontend / Debug Console / TextGoogle Tag Manager is loaded before the default consent is set'=>'Google Tag Manager indlæses, før standardsamtykket er indstillet','Frontend / Debug Console / TextThe following service group is deactivated, empty or does not exist, but is selected in the GTM settings'=>'Følgende servicegruppe er deaktiveret, tom eller findes ikke, men er valgt i GTM-indstillingerne','Frontend / Debug Console / TextGoogle Tag Manager package is not installed, but there is a service with the ID "google-tag-manager".'=>'Google Tag Manager-pakken er ikke installeret, men der er en service med ID\'et "google-tag-manager".','Frontend / Debug Console / TextGoogle Tag Manager package is not installed.'=>'Google Tag Manager-pakken er ikke installeret.','Frontend / Debug Console / TextAll selected GTM service groups are active and contain services.'=>'Alle valgte GTM-servicegrupper er aktive og indeholder servicer.','Frontend / Debug Console / TextNo vendors are configured'=>'Ingen leverandører er konfigureret','Frontend / Debug Console / TextList of all services incl. configuration'=>'Liste over alle servicer inkl. konfiguration','Frontend / Debug Console / TextProtocol'=>'Protokol','Frontend / Debug Console / TextDisabled'=>'Deaktiveret','Frontend / Debug Console / TextEnabled'=>'Aktiveret','Frontend / Debug Console / Textinstalled'=>'installeret','Frontend / Debug Console / Textnot installed'=>'ikke installeret','Frontend / Debug Console / TextSettings key "{{ settingsKey }}" is undefined, please report to developer'=>'Indstillingsnøgle "{{ settingsKey }}" er udefineret, rapportér til udvikleren','Backend / ThirdPartyImporter / Component TypeContent Blocker'=>'Indholdsblokker','Backend / ThirdPartyImporter / Component TypeScript Blocker'=>'Scriptblokker','Backend / ThirdPartyImporter / Component TypeService'=>'Service','Backend / ThirdPartyImporter / Component TypeService Group'=>'Servicegruppe','Backend / Plugin Settings / Field<translation-key id="Enable-Debug-Console">Enable Debug Console</translation-key>'=>'<translation-key id="Enable-Debug-Console">Aktivér debugging-konsol</translation-key>','Backend / Dashboard / HintThe debug console helps identify and resolve issues with <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>. It is visible only to administrators and is not shown to your website visitors. '=>'Debugging-konsollen hjælper med at identificere og løse problemer med <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>. Den er kun synlig for administratorer og vises ikke for besøgende på din hjemmeside. ','Frontend / Debug Console / ButtonToggle {{ type }} Entries'=>'Skift {{ type }} poster','Frontend / Debug Console / HeadlineBorlabs Cookie - Debug Console'=>'Borlabs Cookie - Debugging-konsol','Frontend / Debug Console / TableAdditional Information'=>'Yderligere information','Frontend / Debug Console / TableResult'=>'Resultat','Frontend / Debug Console / TableTest'=>'Test','Frontend / Debug Console / TextConfig is loaded'=>'Konfig er indlæst','Frontend / Debug Console / TextCookie Domain is set correctly'=>'Domæne for cookie er indstillet korrekt','Frontend / Debug Console / TextBase URL'=>'Basis-URL','Frontend / Debug Console / TextGoogle dataLayer'=>'Google dataLayer','Frontend / Debug Console / TextGoogle Tag Manager'=>'Google Tag Manager','Frontend / Debug Console / TextIAB TCF is disabled'=>'IAB TCF er deaktiveret','Frontend / Debug Console / TextIAB TCF is enabled and vendors are configured'=>'IAB TCF er aktiveret, og leverandører er konfigureret','Frontend / Debug Console / TextBorlabs Cookie is installed'=>'Borlabs Cookie er installeret','Frontend / Debug Console / TextPlugin URL is set correctly'=>'Plugin-URL er indstillet korrekt','Frontend / Debug Console / TextRespect <translation-key id="Do-Not-Track">&quot;Do Not Track&quot;</translation-key>'=>'Respektér <translation-key id="Do-Not-Track">&quot;Do Not Track&quot;</translation-key>','Frontend / Debug Console / TextServices'=>'Servicer','Frontend / Debug Console / TextCode execution is disabled'=>'Kodeudførelse er deaktiveret','Frontend / Debug Console / TextCode execution is not disabled'=>'Kodeudførelse er ikke deaktiveret','Backend / System Check / Alert MessageYour multilingual configuration is incorrect; no languages have been set up.'=>'Din flersprogede konfiguration er forkert; der er ikke oprettet noget sprog.','Backend / Library Settings / FieldE-mail Notifications for &quot;Auto Update: Enabled&quot; Packages'=>'E-mailnotifikationer for &quot;Automatisk opdatering: Aktiveret&quot; Pakker','Backend / Library Settings / TextNotifications about automatic updates are sent to this address.'=>'Meddelelser om automatiske opdateringer sendes til denne adresse.','Backend / HTTP Client / AlertNo connection could be established: "<strong><em>{{ errorMessage }}</em></strong>". Please copy this error message and contact support.'=>'Ingen forbindelse kunne etableres: "<strong><em>{{ errorMessage }}</em></strong>". Kopiér denne fejlmeddelelse, og kontakt support.','Backend / HTTP Client / AlertThe requested method "{{ method }}" is not supported by the HTTP client.'=>'Den ønskede metode "{{ method }}" støttes ikke af HTTP-klienten.','ExceptionThe required argument of type "<strong>ServiceGroupRepository</strong>" is missing for the component "<strong>{{ componentName }} <em>({{ componentKey }})</em></strong>" of model "<strong>{{ model }}</strong>". Please copy this error message and contact support.'=>'Det påkrævede argument af typen "<strong>ServiceGroupRepository</strong>" mangler for komponenten<strong>{{ componentName }} <em>({{ componentKey }})</em></strong>" i modellen "<strong>{{ model }}</strong>". Kopiér denne fejlmeddelelse, og kontakt support.','Backend / Library Settings / Headline<translation-key id="Auto-Update-Settings">Auto Update Settings</translation-key>'=>'<translation-key id="Auto-Update-Settings">Indstillinger for automatisk opdatering</translation-key>','Backend / Shared Mail Strings / TextYou can manage the recipient email addresses for this notification under <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-Library">Library</translation-key>, in the "<translation-key id="Auto-Update-Settings">Auto Update Settings</translation-key>" section at the bottom.'=>'Du kan administrere e-mailadresserne for modtagerne af denne meddelelse under <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-Library">Bibliotek</translation-key> i sektionen "<translation-key id="Auto-Update-Settings">Indstillinger for automatisk opdatering</translation-key>" nederst.','Backend / Library Settings / FieldE-mail Notifications for &quot;Auto Update: Disabled&quot; Packages'=>'E-mailnotifikationer for &quot;Automatisk opdatering: Deaktiveret&quot; Pakker','Backend / Library Settings / HintIf enabled, you will receive an e-mail notification when a package is available for updating, even if the auto update is disabled.'=>'Hvis aktiveret vil du modtage en e-mail, når en pakke er tilgængelig til at blive opdateret, selv hvis den automatiske opdatering er deaktiveret.','Backend / Library Settings / HintAdd one e-mail address per line to which the notification is to be sent. Enter at least one email address.'=>'Tilføj en e-mailadresse pr. linje, som meddelelsen skal sendes til. Indtast mindst én e-mailadresse.','Backend / Content Blockers / Option<translation-key id="Preset-D">Preset D</translation-key> - Floating Icon'=>'<translation-key id="Preset-D">Skabelon D</translation-key> - Flydende ikon','Seeder / Default Content Blocker / A11YMore information about the blocked content.'=>'Flere oplysninger om det blokerede indhold.','Backend / Dialog Settings / LabelShow <translation-key id="Dialog">Dialog</translation-key> After User Interaction'=>'Vis <translation-key id="Dialog">Dialogboks</translation-key> efter brugerinteraktion','Backend / Dialog Settings / HintIf enabled, the <translation-key id="Dialog">Dialog</translation-key> is shown after the user interacts with the page (e.g., by clicking, scrolling, or pressing a key). The option <translation-key id="Show-Dialog">Show Dialog</translation-key> must be enabled. Enabling this option can enhance your website\'s <translation-key id="Web-Vitals">Web Vitals</translation-key> score, but it may also negatively impact the user experience.'=>'Hvis aktiveret så vises <translation-key id="Dialog">Dialogboksen</translation-key>, når brugeren har interageret med siden (f.eks. ved at klikke, scrolle eller trykke på en tast). Indstillingen <translation-key id="Show-Dialog">Vis dialogboks</translation-key> skal være aktiveret. Aktivering af denne indstilling kan forbedre din hjemmesides <translation-key id="Web-Vitals">Web Vitals</translation-key>-score, men det kan også have en negativ indvirkning på brugeroplevelsen.','Backend / Package Install Failed Mail / TextLog in to your WordPress account, navigate to <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>, and check the log with the <translation-key id="Process-ID">Process ID</translation-key> "<strong>{{ processId }}</strong>" for more information.'=>'Log ind på din WordPress-konto, gå til <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> &raquo; <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>, og tjek loggen med <translation-key id="Process-ID">Proces-id</translation-key>\'et "<strong>{{ processId }}</strong>" for at få flere oplysninger.','Backend / Package Auto Update Failed Mail / TextBorlabs Cookie: Automatic Update of {{ packageName }} failed'=>'Borlabs Cookie: Automatisk opdatering af {{ packageName }} mislykkedes','Backend / Planned Package Auto Update Mail / Table HeadlineOverwrite Code'=>'Overskriv kode','Backend / Planned Package Auto Update Mail / Table HeadlineOverwrite Translation'=>'Overskriv oversættelse','Backend / Planned Package Auto Update Mail / Table HeadlinePlanned for'=>'Planlagt til','Backend / Planned Package Auto Update Mail / TextAn automatic update is planned for the following <strong>Borlabs Cookie</strong> packages:'=>'Der er planlagt en automatisk opdatering af følgende <strong>Borlabs Cookie</strong>-pakker:','Backend / Planned Package Auto Update Mail / TextBorlabs Cookie: {{ numberOfAutomaticPackageUpdates }} Automatic Updates Planned, {{ numberOfManualPackageUpdates }} Manual Updates Required'=>'Borlabs Cookie: {{ numberOfAutomaticPackageUpdates }} Automatiske opdateringer planlagt, {{ numberOfManualPackageUpdates }} Manuelle opdateringer påkrævet','Backend / Planned Package Auto Update Mail / TextUpdates are available for the following <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> packages, but must be updated manually as their automatic updating is disabled:'=>'Der findes opdateringer til følgende <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>-pakker, men de skal opdateres manuelt, da deres automatiske opdatering er deaktiveret:','Backend / Shared Mail Strings / TextThis email is sent from <a href="{{ websiteUrl }}"><strong>{{ websiteName }}</strong></a>.'=>'Denne e-mail er sendt fra <a href="{{ websiteUrl }}"><strong>{{ websiteName }}</strong></a>.','Backend / Log / Field<translation-key id="Process-ID">Process ID</translation-key>'=>'<translation-key id="Process-ID">Proces-id</translation-key>','Backend / Log / Table Headline<translation-key id="Process-ID">Process ID</translation-key>'=>'<translation-key id="Process-ID">Proces-id</translation-key>','Backend / Page Manager / Menu Title- Jobs'=>'- Opgaver','Backend / Page Manager / Site TitleJobs'=>'Opgaver','Backend / System Check / Table HeadlineJobs'=>'Opgaver','Backend / Init / OptionEvery 5 Minutes'=>'Hvert 5. minut','Backend / Library / HintIf enabled, the text is overwritten with the translation provided by the package when the package is automatically updated. To retain your translation while only updating the component settings, you may disable this option.'=>'Hvis aktiveret overskrives teksten med den oversættelse, der udbydes af pakken, når pakken opdateres automatisk. Hvis du vil beholde din oversættelse, mens du kun opdaterer komponentindstillingerne, kan du deaktivere denne mulighed.','Backend / Library Settings / HintSet the time for automatic package updates. All updates are scheduled according to UTC-0.'=>'Indstil tidspunktet for automatiske pakkeopdateringer. Alle opdateringer er planlagt i henhold til UTC-0.','Backend / Library / TextAuto Update planned for'=>'Automatisk opdatering planlagt til','Backend / Library / Things to knowIf enabled, this feature will automatically update the package to its most recent version. We strongly recommend enabling this setting to enhance both compatibility and security.'=>'Hvis aktiveret vil denne funktion automatisk opdatere pakken til den nyeste version. Vi anbefaler på det kraftigste at aktivere denne indstilling for at forbedre både kompatibilitet og sikkerhed.','Backend / Library / Things to knowAdditionally, we advise allowing automatic updates to overwrite existing code and translations to guarantee optimal functionality.'=>'Derudover anbefaler vi at lade automatiske opdateringer overskrive eksisterende kode og oversættelser for at garantere optimal funktionalitet.','Backend / Library / Things to knowYou will receive an e-mail notification at least 24 hours prior to the automatic update of the package.'=>'Du modtager en e-mailnotifikation mindst 24 timer før den automatiske opdatering af pakken.','Backend / Library Settings / Things to knowAuto Update Interval'=>'Automatisk opdateringsinterval','Backend / Library Settings / Things to knowAuto Update Symbol'=>'Automatisk opdateringssymbol','Backend / Library Settings / HintSet the schedule for automatic package updates. By default, updates take place after at least 24 hours. Alternatively, you can specify a day of the week on which the updates should take place. There must be at least 24 hours between the time the update is detected and the desired day of the week.'=>'Indstil tidsplanen for automatiske pakkeopdateringer. Som standard finder opdateringer sted efter mindst 24 timer. Alternativt kan man angive en ugedag, hvor opdateringerne skal finde sted. Der skal være mindst 24 timer mellem det tidspunkt, hvor opdateringen registreres, og den ønskede ugedag.','Backend / Library Settings / Things to knowExample: If your planned day of the week is Wednesday 23:00 and the update was published on Tuesday at 15:00, Wednesday of the following week will be selected, even if the 24-hour minimum interval was observed.'=>'Eksempel: Hvis din planlagte ugedag er onsdag kl. 23:00, og opdateringen blev offentliggjort tirsdag kl. 15:00, vælges onsdag i den følgende uge, selv om minimumsintervallet på 24 timer blev overholdt.','Backend / Library Settings / Things to knowThe symbol indicates that automatic updates are enabled for this package.'=>'Symbolet viser, at automatiske opdateringer er aktiveret for denne pakke.','Backend / Planned Package Auto Update Mail / Table HeadlineInstalled Version'=>'Installeret version','Backend / Planned Package Auto Update Mail / Table HeadlineLatest Version'=>'Seneste version','Backend / Planned Package Auto Update Mail / Table HeadlinePackage'=>'Pakke','Backend / Package Install Failed Mail / TextThe automatic installation of the package &quot;<strong>{{ packageName }}</strong>&quot; failed.'=>'Den automatiske installation af pakken &quot;<strong>{{ packageName }}</strong>&quot; mislykkedes.','Backend / Library / Auto Update IntervalAfter 24 hours'=>'Efter 24 timer','Backend / Library / Auto Update IntervalMonday'=>'Mandag','Backend / Library / Auto Update IntervalTuesday'=>'Tirsdag','Backend / Library / Auto Update IntervalWednesday'=>'Onsdag','Backend / Library / Auto Update IntervalThursday'=>'Torsdag','Backend / Library / Auto Update IntervalFriday'=>'Fredag','Backend / Library / Auto Update IntervalSaturday'=>'Lørdag','Backend / Library / Auto Update IntervalSunday'=>'Søndag','ExceptionEntry with key {{ key }} of model {{ model }} not found for language {{ language }}.'=>'Post med nøgle {{ key }} af model {{ model }} ikke fundet for sprog {{ language }}.','Backend / Job / Alert MessageThe <translation-key id="Job">Job</translation-key> could not be found.'=>'<translation-key id="Job">Opgaven</translation-key> kunne ikke findes.','Backend / Job / Breadcrumb<translation-key id="Jobs">Jobs</translation-key>'=>'<translation-key id="Jobs">Opgaver</translation-key>','Backend / Job / BreadcrumbDetails'=>'Oplysninger','Backend / Job / FieldCreated at'=>'Oprettet den','Backend / Job / FieldExecuted at'=>'Udført den','Backend / Job / Field<translation-key id="ID">ID</translation-key>'=>'<translation-key id="ID">ID</translation-key>','Backend / Job / FieldPayload'=>'Payload','Backend / Job / FieldPlanned for'=>'Planlagt til','Backend / Job / FieldType'=>'Type','Backend / Job / Alert MessageNo <translation-key id="Jobs">Jobs</translation-key> found.'=>'Ingen <translation-key id="Jobs">Opgaver</translation-key> fundet.','Backend / Job / Headline<translation-key id="Jobs">Jobs</translation-key>'=>'<translation-key id="Jobs">Opgaver</translation-key>','Backend / Job / PlaceholderSearch Type or Payload'=>'Søg efter type eller payload','Backend / Job / Table HeadlineCreated at'=>'Oprettet den','Backend / Job / Table HeadlineExecuted at'=>'Udført den','Backend / Job / Table Headline<translation-key id="ID">ID</translation-key>'=>'<translation-key id="ID">ID</translation-key>','Backend / Job / Table HeadlinePayload'=>'Payload','Backend / Job / Table HeadlinePlanned for'=>'Planlagt til','Backend / Job / Table HeadlineType'=>'Type','Backend / Global / Navigation Entry<translation-key id="Navigation-System-Jobs">Jobs</translation-key>'=>'<translation-key id="Navigation-System-Jobs">Opgaver</translation-key>','Backend / Library / FieldEnable Auto Update'=>'Aktivér automatisk opdatering','Backend / Library / FieldOverwrite Code on Auto Update'=>'Overskriv kode ved automatisk opdatering','Backend / Library / FieldOverwrite Translation on Auto Update'=>'Overskriv oversættelse ved automatisk opdatering','Backend / Library Settings / FieldE-mail Addresses'=>'E-mail-adresser','Backend / Library Settings / FieldAuto Update Interval'=>'Automatisk opdateringsinterval','Backend / Library Settings / FieldAuto Update Time Span'=>'Automatisk opdateringstid','Backend / Library / HintIf enabled, the package will be automatically updated to the latest version.'=>'Hvis aktiveret bliver pakken automatisk opdateret til den nyeste version.','Backend / Library / HintIf enabled, the code (<translation-key id="Content-Blocker">Content Blocker</translation-key>: <translation-key id="Preview-Blocked-Content-Image">Image</translation-key>, <translation-key id="Preview-Blocked-Content-HTML">HTML</translation-key>, <translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>, <translation-key id="Global">Global</translation-key> and <translation-key id="Initialization">Initialization</translation-key>;<br><translation-key id="Service">Service</translation-key>: <translation-key id="Opt-in-Code">Opt-in Code</translation-key>, <translation-key id="Opt-out-Code">Opt-out Code</translation-key> and <translation-key id="Fallback-Code">Fallback Code</translation-key>) will be overwritten with the code provided by the package. To retain your code modifications while only updating the component settings, you may disable this option.'=>'Hvis aktiveret så vil koden (<translation-key id="Content-Blocker">Indholdsblokker</translation-key>: <translation-key id="Preview-Blocked-Content-Image">Billede</translation-key>, <translation-key id="Preview-Blocked-Content-HTML">HTML</translation-key>, <translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>, <translation-key id="Global">Global</translation-key> og <translation-key id="Initialization">Initialisering</translation-key>;<br><translation-key id="Service">Service</translation-key>: <translation-key id="Opt-in-Code">Opt-in-kode</translation-key>, <translation-key id="Opt-out-Code">Opt-out-kode</translation-key> og <translation-key id="Fallback-Code">Fallback-kode</translation-key>) blive overskrevet med den kode, der udbydes af pakken. Hvis du vil beholde dine kodeændringer, mens du kun opdaterer komponentindstillingerne, kan du deaktivere denne mulighed.','Backend / Plugin Update / Optiona) <translation-key id="All-versions">All versions</translation-key> (recommended)'=>'a) <translation-key id="All-versions">Alle versioner</translation-key>','Backend / Plugin Settings / Things to know / Text<translation-key id="Minor-versions">Minor versions</translation-key>: <translation-key id="MINOR">MINOR</translation-key>, <translation-key id="PATCH">PATCH</translation-key> and <translation-key id="HOTFIX">HOTFIX</translation-key> versions are installed automatically.'=>'<translation-key id="Minor-versions">Mindre versioner</translation-key>: <translation-key id="MINOR">MINDRE</translation-key>-, <translation-key id="PATCH">PATCH</translation-key>- og <translation-key id="HOTFIX">HOTFIX</translation-key>-versioner installeres automatisk.','Backend / Plugin Settings / Things to know / Text<translation-key id="Patch-versions">Patch versions</translation-key>: <translation-key id="PATCH">PATCH</translation-key> and <translation-key id="HOTFIX">HOTFIX</translation-key> versions are installed automatically.'=>'<translation-key id="Patch-versions">Patch-versioner</translation-key>: <translation-key id="PATCH">PATCH</translation-key> og <translation-key id="HOTFIX">HOTFIX</translation-key>-versioner installeres automatisk.','Backend / API Client / AlertThe license key has been blocked for this domain. Check your license key in our customer portal <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'Licensnøglen er blevet blokeret for dette domæne. Tjek din licensnøgle i vores kundeportal <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / API Client / AlertIt is not possible to register another website with this license key. Remove the license key from another website to register it here. Check your license key in our customer portal <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'Det er ikke muligt at registrere en anden hjemmeside med denne licensnøgle. Fjern licensnøglen fra en anden hjemmeside for at registrere den her. Tjek din licensnøgle i vores kundeportal <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / API Client / AlertYour site data is not valid. To remove the license key, please use our customer portal. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'Dine hjemmesidedata er ikke gyldige. Brug vores kundeportal for at fjerne licensnøglen. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>service.borlabs.io</span><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / License / LabelConfirm license removal'=>'Bekræft licensfjernelse','Backend / API Client / AlertThe license key is missing. Please enter a license key.'=>'Licensnøglen mangler. Indtast en licensnøgle.','Backend / Dashboard / TextLocalization'=>'Lokalisering','Backend / Cloud Scan / TipEnsure that your website is publicly accessible and not hindered by any <strong><em>Maintenance</em></strong> or <strong><em>Under construction</em></strong> page plugins.'=>'Sørg for, at din hjemmeside er offentligt tilgængelig og ikke hindret af nogen sideplugins som <strong><em>vedligeholdelse</em></strong> eller <strong><em>Under opbygning</em></strong>.','Backend / Cloud Scan / Things to know / HeadlineHow the scanner works'=>'Sådan fungerer scanneren','Backend / Cloud Scan / TipThe scanner will visit your website and analyze the cookies and external resources that are loaded.'=>'Scanneren besøger din hjemmeside og analyserer de cookies og eksterne ressourcer, der er indlæst.','Backend / Cloud Scan / TipIn cases where your website is secured through HTTP authentication, kindly refer to the subsequent section for detailed guidance on HTTP authentication.'=>'I tilfælde, hvor din hjemmeside er sikret via HTTP-godkendelse, så referér venligst til den efterfølgende sektion for en detaljeret vejledning om HTTP-godkendelse.','Seeder / Default Service Group / DescriptionUnclassified services are services that we are in the process of classifying. Only limited information about the use of the data and its purpose is available for these services.'=>'Uklassificerede servicer er servicer, som vi er i færd med at klassificere. Kun begrænsede oplysninger om brugen af data og deres formål er tilgængelige for disse servicer.','Seeder / Default Service Group / NameUnclassified'=>'Uklassificeret','Backend / Settings / LabelPlugin URL'=>'Plugin-URL','Backend / Settings / HintThe URL of the <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> plugin directory.'=>'URL\'en til plugin-biblioteket for <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.','Backend / Services / OptionsProcessing Location'=>'Dataplacering','Frontend / Dialog / Table HeadlineProcessing Location'=>'Dataplacering','Backend / Dialog Settings / HintIf enabled, the appearance of the <translation-key id="Dialog">Dialog</translation-key> is delayed for two seconds.'=>'Hvis aktiveret fremgår <translation-key id="Dialog">Dialogboksen</translation-key> to sekunder senere.','Backend / Dashboard / HintThis setting should only be activated when urgently required. When activated, it generates a large number of log entries that can affect the performance of the website. The log entries can be found under <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logs</translation-key>.'=>'Denne indstilling bør kun aktiveres, når det er strengt nødvendigt. Når den er aktiveret, genererer den et stort antal logposter, som kan påvirke hjemmesidens ydeevne. Logposterne kan findes under <translation-key id="Navigation-System">System</translation-key> &raquo; <translation-key id="Navigation-System-Logs">Logfiler</translation-key>.','Backend / Global / Alert MessageSome <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> files have been blocked by a browser extension. Please deactivate your ad blocker or cookie notice blocker.'=>'Nogle <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>-filer er blevet blokeret af en browserudvidelse. Deaktivér din ad blocker eller cookie notice blocker.','Backend / IAB TCF Configure Vendors / Things to know<translation-key id="IAB-TCF-Feature">Feature</translation-key>'=>'<translation-key id="IAB-TCF-Feature">Funktion</translation-key>','Backend / IAB TCF Configure Vendors / Things to know<translation-key id="IAB-TCF-Purpose">Purpose</translation-key>'=>'<translation-key id="IAB-TCF-Purpose">Formål</translation-key>','Backend / IAB TCF Configure Vendors / Things to know<translation-key id="IAB-TCF-Special-Feature">Special Feature</translation-key>'=>'<translation-key id="IAB-TCF-Special-Feature">Særlig funktion</translation-key>','Backend / IAB TCF Configure Vendors / Things to know<translation-key id="IAB-TCF-Special-Purpose">Special Purpose</translation-key>'=>'<translation-key id="IAB-TCF-Special-Purpose">Særligt formål</translation-key>','Backend / IAB TCF Configure Vendors / Field<translation-key id="IAB-TCF-Features">Features</translation-key>'=>'<translation-key id="IAB-TCF-Features">Funktioner</translation-key>','Backend / IAB TCF Configure Vendors / Field<translation-key id="IAB-TCF-Purposes">Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Purposes">Formål</translation-key>','Backend / IAB TCF Configure Vendors / Field<translation-key id="IAB-TCF-Special-Features">Special Features</translation-key>'=>'<translation-key id="IAB-TCF-Special-Features">Særlige funktioner</translation-key>','Backend / IAB TCF Configure Vendors / Field<translation-key id="IAB-TCF-Special-Purposes">Special Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Special-Purposes">Særlige formål</translation-key>','Backend / Settings / Things to know / TextDepending on your <translation-key id="Multisite-Network">Multisite Network</translation-key> settings you can separate the consents, or have to aggregate them to get a complete consent history.'=>'Afhængigt af dit <translation-key id="Multisite-Network">Multisite Network</translation-key>-indstillinger kan du adskille samtykkerne eller være nødt til at samle dem for at få en komplet samtykkehistorik.','Backend / Page Manager / Menu Title- Logs'=>'- Logfiler','Backend / Page Manager / Site TitleLogs'=>'Logfiler','Backend / Global / Navigation Entry<translation-key id="Navigation-System-Logs">Logs</translation-key>'=>'<translation-key id="Navigation-System-Logs">Logfiler</translation-key>','Backend / Settings / Things to know / Alert MessageYour WordPress is not a <translation-key id="Multisite-Network">Multisite Network</translation-key>, therefore you do not have do modify this setting in most cases.'=>'Din WordPress er ikke et <translation-key id="Multisite-Network">Multisite Network</translation-key>, og derfor behøver du i de fleste tilfælde ikke at ændre denne indstilling.','Backend / IAB TCF Configure Vendors / Things to knowThis view is used solely to activate all vendors based on the purposes, features, etc. The TCF aims to display adverts from vendors for which consent has been given based on these features. Therefore, the checkboxes will not be selected again when you call them up again.'=>'Denne visning bruges udelukkende til at aktivere alle leverandører baseret på formål, funktioner osv. TCF har til formål at vise annoncer fra leverandører, som der er givet samtykke til baseret på disse funktioner. Afkrydsningsfelterne vil derfor ikke blive markeret igen, når du kalder dem op igen.','Backend / Dialog Settings / Things to know / Text<translation-key id="Language-Switcher-Code">Code</translation-key>: Enter the language code of the language you want to add, e.g. <strong><em>de</em></strong>. The language code must be in <translation-key id="ISO-639-1">ISO 639-1</translation-key> format. You can find a list of all language codes <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank"><strong><em>here</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'<translation-key id="Language-Switcher-Code">Kode</translation-key>: Indtast sprogkoden for det sprog, du vil tilføje, f.eks. <strong><em>de</em></strong>. Sprogkoden skal være i <translation-key id="ISO-639-1">ISO 639-1-format</translation-key>. Du kan finde en liste over alle sprogkoder <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank"><strong><em>her</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / Setup Assistant / Things to know / Text<translation-key id="Language-Switcher-Name">Name</translation-key>: Enter the name of the language, e.g. <strong><em>Deutsch</em></strong>.'=>'<translation-key id="Language-Switcher-Name">Navn</translation-key>: Indtast navnet på sproget, f.eks. <strong><em>Deutsch</em></strong>.','Backend / Dialog Settings / Things to know / Text<translation-key id="Language-Switcher-URL">URL</translation-key>: Enter the URL of the page of the language.'=>'<translation-key id="Language-Switcher-URL">URL</translation-key>: Indtast URL\'en til sprogets side.','Backend / Dialog Settings / Things to know / TextThe <translation-key id="Language-Switcher">Language Switcher</translation-key> allows visitors to change the website\'s language using the <translation-key id="Dialog">Dialog</translation-key>. Once they choose a language, they\'re automatically taken to the website\'s version in that language. This feature requires a multilingual plugin or a <translation-key id="Multisite-Network">Multisite Network</translation-key>.'=>'<translation-key id="Language-Switcher">Sprogomskifteren</translation-key> giver besøgende mulighed for at ændre hjemmesidens sprog ved hjælp af <translation-key id="Dialog">Dialogboksen</translation-key>. Når de har valgt et sprog, kommer de automatisk til hjemmesidens version på det pågældende sprog. Denne funktion kræver et flersproget plugin eller et <translation-key id="Multisite-Network">Multisite Network</translation-key>.','Backend / Dialog Settings / TableLanguage'=>'Sprog','Backend / Dialog Settings / TableLanguage Code'=>'Sprogkode','Backend / Dialog Settings / TableURL'=>'URL','Backend / Dialog Settings / Things to know / HeadlineWhat is the purpose of the <translation-key id="Language-Switcher">Language Switcher</translation-key> section?'=>'Hvad er formålet med sektionen <translation-key id="Language-Switcher">Sprogomskifter</translation-key>?','Backend / Dialog Settings / Things to know / HeadlineInput fields explained'=>'Inputfelter forklaret','Frontend / Dialog / Link TextLanguage'=>'Sprog','Backend / Dialog Localization / LabelLanguage Switcher - Link Text'=>'Sprogomskifter - Linktekst','Backend / Dialog Settings / Alert MessageNo <translation-key id="Language-Option">Language Option</translation-key> configured.'=>'Ingen <translation-key id="Language-Option">Sprogindstilling</translation-key> konfigureret.','Backend / Dialog Settings / Button TitleAdd Language Option'=>'Tilføj sprogindstilling','Backend / Dialog Settings / HeadlineLanguage Switcher'=>'Sprogomskifter','Backend / System Check / Table HeadlineConsent Statistic by Day - <translation-key id="Service-Groups">Service Groups</translation-key>'=>'Samtykkestatistikker fordelt på dag - <translation-key id="Service-Groups">Servicegrupper</translation-key>','Backend / System Check / Table HeadlineConsent Statistic by Day - <translation-key id="Services">Services</translation-key>'=>'Samtykkestatistikker fordelt på dag - <translation-key id="Services">Servicer</translation-key>','Backend / System Check / Table HeadlineConsent Statistic by Hour - <translation-key id="Service-Groups">Service Groups</translation-key>'=>'Samtykkestatistikker fordelt på time - <translation-key id="Service-Groups">Servicegrupper</translation-key>','Backend / System Check / Table HeadlineConsent Statistic by Hour - <translation-key id="Services">Services</translation-key>'=>'Samtykkestatistikker fordelt på time - <translation-key id="Services">Servicer</translation-key>','Backend / Page Manager / Menu Title- Import &amp; Export'=>'- Import og eksport','Backend / Page Manager / Menu TitleImport &amp; Export'=>'Import og eksport','Backend / Validation / Alert MessageThe value in the <strong>{{ fieldName }}</strong> field is not valid JSON.'=>'Værdien i feltet <strong>{{ fieldName }}</strong> er ikke gyldig JSON.','Backend / Library / HintIf enabled, the code (<translation-key id="Opt-in-Code">Opt-in Code</translation-key>, <translation-key id="Opt-out-Code">Opt-out Code</translation-key> and <translation-key id="Fallback-Code">Fallback Code</translation-key>) will be overwritten with the code provided by the package. To retain your code modifications while only updating the component settings, you may disable this option.'=>'Hvis aktiveret vil koden (<translation-key id="Opt-in-Code">Opt-in-kode</translation-key>, <translation-key id="Opt-out-Code">Opt-out-kode</translation-key> og <translation-key id="Fallback-Code">Fallback-kode</translation-key>) blive overskrevet med den kode, der udbydes af pakken. Hvis du vil beholde dine kodeændringer og kun opdatere komponentindstillingerne, kan du deaktivere denne mulighed.','Backend / Services / LabelDisable Code Execution'=>'Deaktivér kodeudførelse','Backend / Services / HintIf enabled, this <translation-key id="Service">Service</translation-key> refrains from executing any JavaScript code. This feature can be valuable if you solely require the consent of the <translation-key id="Service">Service</translation-key> and intend to execute code through a tag management system (TMS).'=>'Hvis den er aktiveret, afholder denne <translation-key id="Service">Service</translation-key> sig fra at udføre JavaScript-kode. Denne funktion kan være værdifuld, hvis du udelukkende har brug for <translation-key id="Service">Servicens</translation-key> samtykke og har til hensigt at udføre kode via et tag management system (TMS).','Backend / Library / Alert MessagePlease use the successor package <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="{{ link }}" target="_blank"><strong><em>{{ name }}</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.'=>'Brug den efterfølgende pakke <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="{{ link }}" target="_blank"><strong><em>{{ name }}</em></strong><span class="brlbs-cmpnt-external-link-icon"></span></a>.','Backend / Library / HintIf enabled, the code (<translation-key id="Preview-Blocked-Content-Image">Image</translation-key>, <translation-key id="Preview-Blocked-Content-HTML">HTML</translation-key>, <translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>, <translation-key id="Global">Global</translation-key> and <translation-key id="Initialization">Initialization</translation-key>) will be overwritten with the code provided by the package. To retain your code modifications while only updating the component settings, you may disable this option.'=>'Hvis aktiveret vil koden<translation-key id="Preview-Blocked-Content-Image">Billede</translation-key>, <translation-key id="Preview-Blocked-Content-HTML">HTML</translation-key>, <translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>, <translation-key id="Global">Global</translation-key> og <translation-key id="Initialization">Initialisering</translation-key>) blive overskrevet med den kode, der udbydes af pakken. Hvis du vil beholde dine kodeændringer og kun opdatere komponentindstillingerne, kan du deaktivere denne mulighed.','Backend / Library / Alert MessageThis package has been marked as deprecated and should be uninstalled.'=>'Denne pakke er markeret som forældet og bør afinstalleres.','Backend / Import & Export / Things to knowYou can review which settings will be imported in the list below, labeled as <translation-key id="Importing-the-following-settings">Importing the following settings</translation-key>.'=>'Du kan se, hvilke indstillinger der vil blive importeret på listen nedenfor, der er mærket som <translation-key id="Importing-the-following-settings">Importerer følgende indstillinger</translation-key>.','Backend / Import & Export / Things to knowHow to export settings'=>'Sådan eksporterer du indstillinger','Backend / Import & Export / Things to knowHow to import settings'=>'Sådan importerer du indstillinger','Backend / Import & Export / Things to knowImporting settings from <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> 2.x is currently not feasible and will remain impossible in the future.'=>'Import af indstillinger fra <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> 2.x er i øjeblikket ikke muligt og vil forblive umuligt i fremtiden.','Backend / Import & Export / Things to knowExporting settings such as <translation-key id="Services">Services</translation-key>, <translation-key id="Content-Blockers">Content Blockers</translation-key>, <translation-key id="Providers">Providers</translation-key>, etc. is not feasible and will remain impossible in the future.'=>'Eksport af indstillinger som <translation-key id="Services">Servicer</translation-key>, <translation-key id="Content-Blockers">Indholdsblokkere</translation-key>, <translation-key id="Providers">Udbydere</translation-key> osv. er ikke muligt og vil forblive umuligt i fremtiden.','Backend / Import & Export / Things to knowTo ensure you have the most up-to-date data, it is advisable to consistently rely on the library.'=>'For at sikre, at du har de mest opdaterede data, er det en god idé hele tiden at bruge biblioteket.','Backend / Global / Navigation Entry<translation-key id="Navigation-System-Import-Export">Import &amp; Export</translation-key>'=>'<translation-key id="Navigation-System-Import-Export">Import og eksport</translation-key>','Backend / Content Blockers / Label<translation-key id="Initialization">Initialization</translation-key>'=>'<translation-key id="Initialization">Initialisering</translation-key>','Backend / Content Blockers / Label<translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>'=>'<translation-key id="Preview-Blocked-Content-CSS">CSS</translation-key>','Backend / Dialog Settings / OptionBox - Compact'=>'Boks - Kompakt','Backend / Import & Export / Alert MessageThe imported data is not valid base64 encoded.'=>'De importerede data er ikke gyldigt base64-kodet.','Backend / Import & Export / Alert MessageThe settings have been imported successfully.'=>'Indstillingerne er blevet succesfuldt importeret.','Backend / Import & Export / Alert MessageThe settings have not been imported successfully.'=>'Indstillingerne er ikke blevet importeret korrekt.','Backend / Import & Export / Alert MessageThe imported data is not valid JSON.'=>'De importerede data er ikke gyldig JSON.','Backend / Import & Export / BreadcrumbImport &amp; Export'=>'Import og eksport','Backend / Import & Export / Button<translation-key id="Import-Settings">Import Settings</translation-key>'=>'<translation-key id="Import-Settings">Importér indstillinger</translation-key>','Backend  / Import & Export /  Description List<translation-key id="Importing-the-following-settings">Importing the following settings</translation-key>'=>'<translation-key id="Importing-the-following-settings">Importerer følgende indstillinger</translation-key>','Backend / Import & Export / FieldContent Blocker - Appearance'=>'Indholdsblokker - Udseende','Backend / Import & Export / FieldDialog - Localization'=>'Dialogboks - Lokalisering','Backend / Import & Export / Field<translation-key id="Dialog-Settings">Dialog - Settings</translation-key>'=>'<translation-key id="Dialog-Settings">Dialogboks - Indstillinger</translation-key>','Backend / Import & Export / FieldExport Data'=>'Eksportér data','Backend / Import & Export / FieldImport Data'=>'Importér data','Backend / Import & Export / FieldWidget'=>'Widget','Backend / Import & Export / HeadlineExport Settings'=>'Eksportér indstillinger','Backend / Import & Export / HeadlineImport Settings'=>'Indstillinger for import','Backend / Import & Export / HintThe settings for which <translation-key id="Legal-Information">Legal Information</translation-key> texts should be displayed are part of the <translation-key id="Dialog-Settings">Dialog - Settings</translation-key> data.'=>'Indstillingerne for hvilke tekster med<translation-key id="Legal-Information">Juridisk information</translation-key>, der skal vises, er en del af <translation-key id="Dialog-Settings">Dialogboks - Indstillinger</translation-key>.','Backend / Import & Export / Things to knowChoose the settings you wish to export, then either click the clipboard icon or highlight the text and copy it to your clipboard.'=>'Vælg de indstillinger, du vil eksportere, og klik derefter enten på udklipsholderikonet, eller fremhæv teksten, og kopiér den til din udklipsholder.','Backend / Import & Export / Things to knowPaste the desired settings into the text field, then click the <translation-key id="Import-Settings">Import Settings</translation-key> button.'=>'Indsæt de ønskede indstillinger i tekstfeltet, og klik derefter på knappen <translation-key id="Import-Settings">Importér indstillinger</translation-key>.','Backend / IAB TCF Settings / HintA <translation-key id="Compatibility-Patch">Compatibility Patch</translation-key> or a third-party developer can add a <translation-key id="Hostname">Hostname</translation-key> to the <translation-key id="Hostnames-for-Consent-Addition">Hostnames for Consent Addition</translation-key> list using a filter.'=>'En <translation-key id="Compatibility-Patch">Kompatibilitetsrettelse</translation-key> eller en tredjepartsudvikler kan føje et <translation-key id="Hostname">Værtsnavn</translation-key> til listen <translation-key id="Hostnames-for-Consent-Addition">Værtsnavne til tilføjelse af samtykke</translation-key> med et filter.','Backend / IAB TCF Vendor Details / Description List<translation-key id="IAB-TCF-Features">Features</translation-key>'=>'<translation-key id="IAB-TCF-Features">Funktioner</translation-key>','Backend / IAB TCF Vendor Details / Description List<translation-key id="IAB-TCF-Purposes">Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Purposes">Formål</translation-key>','Backend / IAB TCF Vendor Details / Description List<translation-key id="IAB-TCF-Special-Features">Special Features</translation-key>'=>'<translation-key id="IAB-TCF-Special-Features">Særlige funktioner</translation-key>','Backend / IAB TCF Vendor Details / Description List<translation-key id="IAB-TCF-Special-Purposes">Special Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Special-Purposes">Særlige formål</translation-key>','Backend / IAB TCF / Table<translation-key id="IAB-TCF-Features">Features</translation-key>'=>'<translation-key id="IAB-TCF-Features">Funktioner</translation-key>','Backend / IAB TCF / Table<translation-key id="IAB-TCF-Purposes">Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Purposes">Formål</translation-key>','Backend / IAB TCF / Table<translation-key id="IAB-TCF-Special-Features">Special Features</translation-key>'=>'<translation-key id="IAB-TCF-Special-Features">Særlige funktioner</translation-key>','Backend / IAB TCF / Table<translation-key id="IAB-TCF-Special-Purposes">Special Purposes</translation-key>'=>'<translation-key id="IAB-TCF-Special-Purposes">Særlige formål</translation-key>','Backend / Model Localization / ModelContent Blocker Location'=>'Indholdsblokkeradresse','Backend / Model Localization / ModelService Cookie'=>'Servicecookie','Backend / Model Localization / ModelService Location'=>'Serviceadresse','Backend / Model Localization / ModelService Option'=>'Servicevalgmulighed','Backend / IAB TCF Settings / HeadlineOne <translation-key id="Hostname">Hostname</translation-key> per line. When a <translation-key id="Hostname">Hostname</translation-key> is recognized in an <strong><em>&lt;a&gt;</em></strong> or <strong><em>&lt;img&gt;</em></strong> tag, the consent will be added to the link via the <strong><em>gdpr_consent</em></strong> parameter.'=>'Et <translation-key id="Hostname">Værtsnavn</translation-key> per linje. Når et <translation-key id="Hostname">Værtsnavn</translation-key> genkendes i en <strong><em>&lt;a&gt;</em></strong> eller <strong><em>&lt;img&gt;</em></strong> tag, vil samtykket blive tilføjet til linket via <strong><em>gdpr_samtykket</em></strong> parameter.','Backend / Cloud Scan / HintAdd one URL per line.'=>'Tilføj én URL pr. linje.','Backend / IAB TCF Cookie Box / Headline<translation-key id="IAB-TCF-Features">Features</translation-key> - Headline'=>'<translation-key id="IAB-TCF-Features">Funktioner</translation-key> - Overskrift','Backend / IAB TCF Cookie Box / Headline<translation-key id="IAB-TCF-Purposes">Purposes</translation-key> - Headline'=>'<translation-key id="IAB-TCF-Purposes">Formål</translation-key> - Overskrift','Backend / IAB TCF Cookie Box / Headline<translation-key id="IAB-TCF-Special-Features">Special Features</translation-key> - Headline'=>'<translation-key id="IAB-TCF-Special-Features">Særlige funktioner</translation-key> - Overskrift','Backend / IAB TCF Cookie Box / Headline<translation-key id="IAB-TCF-Special-Purposes">Special Purposes</translation-key> - Headline'=>'<translation-key id="IAB-TCF-Special-Purposes">Særlige formål</translation-key> - Overskrift','Backend / Global / Alert MessageDeleting <strong>{{ modelName }}</strong> <strong><em>{{ modelLabel }}</em></strong> failed.'=>'Sletning af <strong>{{ modelName }}</strong> <strong><em>{{ modelLabel }}</em></strong> mislykkedes.','Backend / IAB TCF Settings / Field<translation-key id="Hostnames-for-Consent-Addition">Hostnames for Consent Addition</translation-key>'=>'<translation-key id="Hostnames-for-Consent-Addition">Værtsnavne til tilføjelse af samtykke</translation-key>','Backend / IAB TCF Settings / FieldThird-Party <translation-key id="Hostnames-for-Consent-Addition">Hostnames for Consent Addition</translation-key> List'=>'Tredjeparts <translation-key id="Hostnames-for-Consent-Addition">Værtsnavne til tilføjelse af samtykke</translation-key>','Backend / Dialog Settings / LabelShow "<translation-key id="Dialog-Close-Button">Close</translation-key>" Button'=>'Vis knappen "<translation-key id="Dialog-Close-Button">Luk</translation-key>"','Backend / Dialog Settings / HintIf enabled, the <translation-key id="Dialog-Close-Button">Close</translation-key> button will be shown to the visitor. Clicking the button is equivalent to choosing <translation-key id="Accept-Only-Essential">Accept Only Essential</translation-key>. This button can be toggled on or off specifically for the <translation-key id="Dialog-Entrance">Dialog Entrance</translation-key>.'=>'Hvis aktiveret vises knappen <translation-key id="Dialog-Close-Button">Luk</translation-key> for den besøgende. At klikke på knappen svarer til at vælge <translation-key id="Accept-Only-Essential">Acceptér kun nødvendige</translation-key>. Denne knap kan slås til eller fra specifikt for <translation-key id="Dialog-Entrance">Dialogboks - Visning</translation-key>.','Backend / Local Scanner / TextClick on <a class="brlbs-cmpnt-link" href="##SIGNED_URL##" target="_bank">this link</a> to scan manually.'=>'Klik på <a class="brlbs-cmpnt-link" href="##SIGNED_URL##" target="_bank">dette link</a> for at scanne manuelt.','Backend / Package Manager Components / AlertA <strong>{{ resource }}</strong> with the key <strong><em>{{ key }}</em></strong> already exists. Please delete the <strong>{{ resource }}</strong> first.'=>'En <strong>{{ resource }}</strong> med nøglen <strong><em>{{ key }}</em></strong> findes allerede. Slet <strong>{{ resource }}</strong> først.','Backend / Dialog Settings / HintIf enabled, the <translation-key id="Save-Selection">Save Selection</translation-key> button will be shown to the visitor, with which the visitor can save their consent preferences. This button can be toggled on or off specifically for the <translation-key id="Dialog-Entrance">Dialog Entrance</translation-key>, but it will always be visible for the <translation-key id="Dialog-Details">Dialog Details</translation-key>.'=>'Hvis aktiveret vises knappen <translation-key id="Save-Selection">Gem valg</translation-key> for den besøgende, hvormed den besøgende kan gemme sine samtykkepræferencer. Knappen kan slås til eller fra specifikt for <translation-key id="Dialog-Entrance">Dialogboks - Visning</translation-key>, men den vil altid være synlig for <translation-key id="Dialog-Details">Dialogboks - Oplysninger</translation-key>.','Backend / IAB TCF Settings / Field<translation-key id="Compact-Layout">Compact Layout</translation-key>'=>'<translation-key id="Compact-Layout">Kompakt layout</translation-key>','Backend / IAB TCF Settings / HintWhen <translation-key id="Compact-Layout">Compact Layout</translation-key> is enabled, the IAB TCF dialog will be displayed in a compact layout, to improve usability on mobile devices.'=>'Når <translation-key id="Compact-Layout">Kompakt layout</translation-key> er aktiveret, vises IAB TCF-dialogboksen i et kompakt layout for at forbedre brugervenligheden på mobile enheder.','Backend / System Check / Table HeadlineWordPress REST API'=>'WordPress REST API','Backend / Dialog Settings / Alert MessageDepending on applicable law, this option may not be allowed to be turned off.'=>'Afhængigt af gældende lovgivning er det muligvis ikke tilladt at slå denne mulighed fra.','Backend / Dialog Settings / LabelShow "<translation-key id="Save-Selection">Save Selection</translation-key>" Button'=>'Vis knappen "<translation-key id="Save-Selection">Gem valg</translation-key>"','Backend / Global / Things to know / TextWe use the term <translation-key id="Synchronize-Translation">Translation</translation-key> to denote the texts associated with this entry. Synchronizing the <translation-key id="Translation">Translation</translation-key> will replace the texts in the selected languages with those from this entry.'=>'Vi bruger termen <translation-key id="Synchronize-Translation">Oversættelse</translation-key> til at betegne de tekster, der er knyttet til denne post. Synkronisering af <translation-key id="Translation">Oversættelse</translation-key> erstatter teksterne på de valgte sprog med dem fra denne post.','Backend / Cloud Scan / AlertUninstalling the <strong>{{ type }}</strong> <strong><em>{{ name }}</em></strong> failed.'=>'Afinstallering af <strong>{{ type }}</strong> <strong><em>{{ name }}</em></strong> mislykkedes.','Backend / Cloud Scan / AlertUninstalling the <strong>{{ type }}</strong> <strong><em>{{ name }}</em></strong> failed: {{ message }}'=>'Afinstallering af <strong>{{ type }}</strong> <strong><em>{{ name }}</em></strong> mislykkedes: {{ message }}','Backend / Cloud Scan / AlertThe package <strong><em>{{ name }}</em></strong> was successfully uninstalled.'=>'Pakken <strong><em>{{ name }}</em></strong> blev succesfuldt afinstalleret.','Backend / Global / Things to know / TextWe use the term <translation-key id="Synchronize-Configuration">Configuration</translation-key> to denote all settings except the texts associated with this entry. Synchronizing the <translation-key id="Configuration">Configuration</translation-key> will set the settings in the selected languages to those of this entry.'=>'Vi bruger termen <translation-key id="Synchronize-Configuration">Konfiguration</translation-key> til at betegne alle indstillinger undtagen de tekster, der er tilknyttet denne post. Synkronisering af <translation-key id="Configuration">Konfiguration</translation-key> sætter indstillingerne for de valgte sprog til indstillingerne for denne post.','Backend / Cloud Scan / FieldHTTP authentication required'=>'HTTP-godkendelse påkrævet','Backend / Cloud Scan / FieldHTTP authentication - Password'=>'HTTP-godkendelse - Adgangskode','Backend / Cloud Scan / FieldHTTP authentication - Username'=>'HTTP-godkendelse - Brugernavn','Backend / Cloud Scan / TipHTTP authentication'=>'HTTP-godkendelse','Backend / Cloud Scan / TipIf your website is protected by HTTP authentication, you can enter the username and password here, to allow the scanner to access your website. The credentials will be deleted after 7 days automatically.'=>'Hvis din hjemmeside er beskyttet af HTTP-godkendelse, kan du indtaste brugernavn og adgangskode her for at give scanneren adgang til din hjemmeside. Legitimationsoplysningerne slettes automatisk efter 7 dage.','Backend / Global / Alert MessageThe <strong>{{ modelName }}</strong> <strong><em>{{ modelLabel }}</em></strong> is still in use by the <strong>{{ blockingModelName }}</strong> <strong><em>{{ blockingModelLabel }}</em></strong>.'=>'Den <strong>{{ modelName }}</strong> <strong><em>{{ modelLabel }}</em></strong> er stadig i brug af <strong>{{ blockingModelName }}</strong> <strong><em>{{ blockingModelLabel }}</em></strong>.','Backend / Global / LabelAdditional Languages'=>'Yderligere sprog','Backend / Global / LabelSynchronize Configuration'=>'Synkronisér konfiguration','Backend / Global / LabelSynchronize Translation'=>'Synkronisér oversættelse','Backend / Global / HintCreate this entry also for other languages.'=>'Opret også denne post til andre sprog.','Backend / Global / HintSets all settings of this configuration as the configuration for the selected languages.'=>'Indstiller alle indstillinger i denne konfiguration som konfigurationen for de valgte sprog.','Backend / Global / HintSet the configuration of this entry as the configuration for the selected languages.'=>'Indstil konfigurationen af denne post som konfiguration for de valgte sprog.','Backend / Global / HintSets all texts of this translation as the texts for the selected languages. The texts are translated automatically.'=>'Indstiller alle tekster i denne oversættelse som tekster for de valgte sprog. Teksterne oversættes automatisk.','Backend / Global / HintSet the translation of this entry as the translation for the selected languages. The texts are translated automatically.'=>'Indstil oversættelsen af denne post som oversættelsen for de valgte sprog. Teksterne oversættes automatisk.','Backend / Global / Things to know / HeadlineSynchronize <translation-key id="Synchronize-Configuration">Configuration</translation-key> Explained'=>'Synkronisér <translation-key id="Synchronize-Configuration">Konfiguration</translation-key> forklaret','Backend / Global / Things to know / HeadlineSynchronize <translation-key id="Synchronize-Translation">Translation</translation-key> Explained'=>'Synkronisér <translation-key id="Synchronize-Translation">Oversættelse</translation-key> forklaret','Backend / License / Alert MessageA valid license is required to use this feature of Borlabs Cookie. <a href="?page=borlabs-cookie-license">Click here</a> to enter your license key, or <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>click here</span><span class="brlbs-cmpnt-external-link-icon"></span></a> to log into your account and purchase a license renewal.'=>'Der kræves en gyldig licens for at bruge denne funktion i Borlabs Cookie. <a href="?page=borlabs-cookie-license">Klik her</a> for at indtaste din licensnøgle, eller <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>klik her</span><span class="brlbs-cmpnt-external-link-icon"></span></a> for at logge ind på din konto og købe en licensfornyelse.','Backend / License / Alert MessageYour license key is not valid for this version. This version of Borlabs Cookie was released after your license has expired, therefore you have to <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>click here</span><span class="brlbs-cmpnt-external-link-icon"></span></a> to log into your account and purchase a license renewal.'=>'Din licensnøgle er ikke gyldig til denne version. Denne version af Borlabs Cookie blev udgivet efter din licens er udløbet, derfor skal du <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" rel="nofollow noreferrer" target="_blank"><span>klikke her</span><span class="brlbs-cmpnt-external-link-icon"></span></a> for at logge ind på din konto og købe en licensfornyelse.','Backend / License / Alert MessagePlease renew your license key to receive updates. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" target="_blank" rel="nofollow noreferrer"><span>Click here</span><span class="brlbs-cmpnt-external-link-icon"></span></a> to log into your account and purchase a license renewal.'=>'Forny din licensnøgle for at modtage opdateringer. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" target="_blank" rel="nofollow noreferrer"><span>Klik her</span><span class="brlbs-cmpnt-external-link-icon"></span></a> for at logge ind på din konto og købe en licensfornyelse.','Backend / License / Alert MessageYour license has expired. This feature is not available with an expired license. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" target="_blank" rel="nofollow noreferrer"><span>Click here</span><span class="brlbs-cmpnt-external-link-icon"></span></a> to log into your account and purchase a license renewal.'=>'Din licens er udløbet. Denne funktion er ikke tilgængelig med en udløbet licens. <a class="brlbs-cmpnt-link brlbs-cmpnt-link-with-icon" href="https://service.borlabs.io/" target="_blank" rel="nofollow noreferrer"><span>Klik her</span><span class="brlbs-cmpnt-external-link-icon"></span></a> for at logge ind på din konto og købe en licensfornyelse.','Backend / Dialog Settings / Things to know / TextCSS Class'=>'CSS-klasse','Backend / Cloud Scan / AlertNo valid pages to scan where sent to the Borlabs Cloud API.'=>'Der blev ikke sendt nogen gyldige sider til Borlabs Cloud API til scanning.','Backend / Cloud Scan / AlertThe scan includes too many pages.'=>'Scanningen indeholder for mange sider.','Backend / Cloud Scan / AlertNo cookie found.'=>'Ingen cookie fundet.','Frontend / Dialog / TextWe need your consent before you can continue on our website.'=>'Vi har brug for dit samtykke, før du kan fortsætte på vores hjemmeside.','Backend / Plugin Settings / Things to know / TextYou can choose how <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> updates automatically. Select from one of the four available options.'=>'Du kan vælge, hvordan <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> opdateres automatisk. Vælg en af de fire tilgængelige muligheder.','Backend / Plugin Settings / Things to know / TextA standard version number follows the format 1.0.3.0, where the segments represent <translation-key id="MAJOR">MAJOR</translation-key>, <translation-key id="MINOR">MINOR</translation-key>, <translation-key id="PATCH">PATCH</translation-key>, and <translation-key id="HOTFIX">HOTFIX</translation-key>, respectively.'=>'Et standardversionsnummer følger formatet 1.0.3.0, hvor segmenterne repræsenterer henholdsvis <translation-key id="MAJOR">STØRRE</translation-key>, <translation-key id="MINOR">MINDRE</translation-key>, <translation-key id="PATCH">PATCH</translation-key> og <translation-key id="HOTFIX">HOTFIX</translation-key>.','Backend / Cloud Scan / TipNote: This column may be empty if the cookie is loaded from another resource, but for which a package is suggested. Once the suggested package is installed, the entry with the blank suggestion column is likely to be removed in the subsequent scan.'=>'Bemærk: Denne kolonne kan være tom, hvis cookien er indlæst fra en anden ressource, men som der foreslås en pakke til. Når den foreslåede pakke er installeret, vil posten med den tomme forslagskolonne sandsynligvis blive fjernet i den efterfølgende scanning.','Backend / Cloud Scan / TipNote: This column may be empty if the resource is loaded from another resource, but for which a package is suggested. Once the suggested package is installed, the entry with the blank suggestion column is likely to be removed in the subsequent scan.'=>'Bemærk: Denne kolonne kan være tom, hvis ressourcen er indlæst fra en anden ressource, men der er foreslået en pakke til den. Når den foreslåede pakke er installeret, vil posten med den tomme forslagskolonne sandsynligvis blive fjernet i den efterfølgende scanning.','Backend / Settings / HintNumber of days until the visitor is asked again for their consent, if the user has only given consent to essential <translation-key id="Services">Services</translation-key>. Remember to adjust the <translation-key id="Cookie-Lifetime">Cookie Lifetime</translation-key> information of the <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> <translation-key id="Cookie">Cookie</translation-key> under <translation-key id="Services">Services</translation-key> &raquo; <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.'=>'Antal dage, indtil den besøgende bliver bedt om samtykke igen, hvis brugeren kun har givet samtykke til nødvendige <translation-key id="Services">Servicer</translation-key>. Husk at justere oplysningerne om <translation-key id="Cookie-Lifetime">Cookielevetid</translation-key> for <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key> <translation-key id="Cookie">Cookie</translation-key> under <translation-key id="Services">Servicer</translation-key> &raquo; <translation-key id="Borlabs-Cookie">Borlabs Cookie</translation-key>.','Backend / Library / Alert MessageAll copyrights, trademarks, and other intellectual property rights mentioned or displayed in this library belong to their respective owners. Unless explicitly stated, these entities are not affiliated, endorsed by, or in any way associated with us.'=>'Alle ophavsrettigheder, varemærker og andre intellektuelle ejendomsrettigheder, der nævnes eller vises i dette bibliotek, tilhører deres respektive ejere. Medmindre det udtrykkeligt er angivet, er disse enheder ikke tilknyttet, støttet af eller på nogen måde forbundet med os.','Backend / System Check / Table HeadlineLibrary Database Last Check with API'=>'Sidste tjek af biblioteksdatabasen med API','Backend / IAB TCF Cookie Box / Text<translation-key id="Tcf-Topic-Personal-Data">Personal Data</translation-key> - Description'=>'<translation-key id="Tcf-Topic-Personal-Data">Personoplysninger</translation-key> - Beskrivelse','Backend / Settings / Label<translation-key id="SameSite-Attribute">SameSite attribute</translation-key>'=>'<translation-key id="SameSite-Attribute">SameSite-attribut</translation-key>','Backend / Plugin Settings / Label<translation-key id="Clear-Third-Party-Cache">Clear Third-Party Cache</translation-key>'=>'<translation-key id="Clear-Third-Party-